function sendJson(res, status, payload, extraHeaders = {}) {
  res.writeHead(status, {
    "content-type": "application/json; charset=utf-8",
    "cache-control": "no-store",
    ...extraHeaders,
  });
  res.end(JSON.stringify(payload));
}

function readBody(req, { raw = false } = {}) {
  return new Promise((resolve, reject) => {
    let body = "";
    req.on("data", (chunk) => {
      body += chunk;
      if (body.length > 1_000_000) {
        reject(new Error("Payload too large"));
        req.destroy();
      }
    });
    req.on("end", () => {
      if (!body) {
        resolve(raw ? { body: {}, raw: "" } : {});
        return;
      }
      try {
        const parsed = JSON.parse(body);
        resolve(raw ? { body: parsed, raw: body } : parsed);
      } catch {
        reject(new Error("Invalid JSON"));
      }
    });
    req.on("error", reject);
  });
}

function verifyPaymentWebhookSignature(req, rawBody) {
  const status = paymentProvider.providerStatus();
  if (!status.webhookSignatureRequired) {
    return { ok: true, required: false, provider: status.provider };
  }
  const secret = process.env.PAYMENT_WEBHOOK_SECRET || "";
  const signature = String(req.headers["x-tradegym-payment-signature"] || "");
  if (!secret || !signature) {
    return {
      ok: false,
      required: true,
      provider: status.provider,
      reason: "missing_payment_webhook_signature",
    };
  }
  const expected = crypto.createHmac("sha256", secret).update(rawBody || "").digest("hex");
  const expectedBuffer = Buffer.from(expected, "hex");
  const signatureBuffer = Buffer.from(signature, "hex");
  if (signatureBuffer.length !== expectedBuffer.length || !crypto.timingSafeEqual(signatureBuffer, expectedBuffer)) {
    return {
      ok: false,
      required: true,
      provider: status.provider,
      reason: "invalid_payment_webhook_signature",
    };
  }
  return { ok: true, required: true, provider: status.provider };
}

function parseCookies(req) {
  const raw = req.headers.cookie || "";
  const cookies = {};
  raw.split(";").forEach((part) => {
    const [key, ...rest] = part.trim().split("=");
    if (key) cookies[key] = decodeURIComponent(rest.join("=") || "");
  });
  return cookies;
}

function sessionFromRequest(db, req) {
  const token = parseCookies(req).tg_session;
  return token ? { token, session: db.sessions[token] || null } : { token: null, session: null };
}

function hashPassword(password, salt = crypto.randomBytes(16).toString("hex")) {
  const hash = crypto.scryptSync(String(password), salt, 64).toString("hex");
  return { salt, hash };
}

function verifyPassword(account, password) {
  if (!account.passwordHash || !account.passwordSalt) return false;
  const { hash } = hashPassword(password, account.passwordSalt);
  return crypto.timingSafeEqual(Buffer.from(hash, "hex"), Buffer.from(account.passwordHash, "hex"));
}

function publicAccount(account) {
  if (!account) return null;
  return {
    id: account.id,
    email: account.email,
    name: account.name,
    role: account.role,
    plan: account.plan,
    emailVerified: account.emailVerified !== false,
    createdAt: account.createdAt || null,
    lastLoginAt: account.lastLoginAt || null,
    complianceAckAt: account.complianceAckAt || null,
    complianceVersion: account.complianceVersion || null,
    complianceRequired: account.complianceVersion !== complianceVersion,
    accountStatus: account.accountStatus || "active",
    disabledAt: account.disabledAt || null,
    disabledReason: account.disabledReason || null,
    legalAcceptanceAt: account.legalAcceptanceAt || null,
    legalVersions: {
      terms: account.termsVersion || null,
      privacy: account.privacyVersion || null,
      risk: account.riskDisclosureVersion || null,
    },
  };
}

function normalizeEmail(value) {
  return String(value || "").trim().toLowerCase();
}

function normalizePlan(value, fallback = "Starter") {
  const plan = String(value || fallback).trim();
  return ["Starter", "Pro Trial", "Pro", "Coach"].includes(plan) ? plan : fallback;
}

function validatePassword(password) {
  if (String(password || "").length < 8) return "Password must be at least 8 characters";
  return null;
}

function validateLegalAcceptance(body) {
  const legal = body.legalAcceptance || {};
  if (legal.accepted !== true) return "Terms, privacy policy, and risk disclosure must be accepted";
  if (legal.termsVersion !== legalVersions.terms) return "Current terms version must be accepted";
  if (legal.privacyVersion !== legalVersions.privacy) return "Current privacy version must be accepted";
  if (legal.riskDisclosureVersion !== legalVersions.risk) return "Current risk disclosure version must be accepted";
  return null;
}

function educationComplianceConstraints() {
  return [
    "Human notes must stay education-only.",
    "No stock recommendation, live signal, guaranteed return, copy-trading instruction, or real-money trading instruction.",
  ];
}

function prohibitedAdviceCheck(input, { field = "text" } = {}) {
  const values = Array.isArray(input) ? input : [input];
  const text = values.map((value) => String(value || "")).join("\n").trim();
  if (!text) return { blocked: false, field, matches: [], constraints: educationComplianceConstraints() };
  const textForChecks = text.replace(
    /\bno\s+stock recommendations?,?\s+live signals?,?\s+(guaranteed returns?|return promises?),?\s+(or\s+)?real-money trading instructions?\b/gi,
    "",
  );
  const checks = [
    { label: "direct buy instruction", pattern: /\b(buy|long)\s+(aapl|tsla|nvda|msft|amzn|meta|googl|goog|spy|qqq|btc|eth)\b/i },
    { label: "direct sell instruction", pattern: /\b(sell|short)\s+(aapl|tsla|nvda|msft|amzn|meta|googl|goog|spy|qqq|btc|eth)\b/i },
    { label: "urgent trade instruction", pattern: /\b(buy now|sell now|enter now|exit now|all in|go all-in)\b/i },
    { label: "live trading signal", pattern: /\b(live signal|entry signal|copy trade|follow this trade|real money trade)\b/i },
    { label: "return guarantee", pattern: /\b(guaranteed profit|guaranteed win|risk-free profit|sure profit)\b/i },
    { label: "romanized buy or sell instruction", pattern: /\b(mai ru|mai chu|zuo duo|zuo kong|xian zai mai|xian zai mai ru|xian zai mai chu|man cang|quan cang)\b/i },
    { label: "romanized return guarantee", pattern: /\b(wen zhuan|bi zhuan|bao zheng ying li|shou yi bao zheng|bao ben)\b/i },
    { label: "romanized live signal or copy trading", pattern: /\b(shi pan xin hao|jin chang xin hao|gen dan|dai dan|shi pan mai mai)\b/i },
  ];
  const phraseChecks = [
    { label: "Chinese buy or sell instruction", phrases: ["\u4e70\u5165", "\u5356\u51fa", "\u505a\u591a", "\u505a\u7a7a", "\u6ee1\u4ed3", "\u5168\u4ed3"] },
    { label: "Chinese live signal or copy trading", phrases: ["\u5b9e\u76d8", "\u4fe1\u53f7", "\u8ddf\u5355", "\u5e26\u5355", "\u8fdb\u573a"] },
    { label: "Chinese return guarantee", phrases: ["\u7a33\u8d5a", "\u5fc5\u8d5a", "\u4fdd\u8bc1\u76c8\u5229", "\u4fdd\u672c"] },
    { label: "mojibake Chinese buy or sell instruction", phrases: ["\u934d\u6827\u569f", "\u6d94\u677f\u53c6", "\u9357\u7470\u5d1f", "\u6d94\u769b\u6130"] },
    { label: "mojibake Chinese live signal or copy trading", phrases: ["\u8dda\u719a\u5d1f", "\u7039\u70bd\u6d30", "\u6dc7\u2033\u5f7f", "\u4fe1\u53f7"] },
  ];
  const matches = checks
    .filter((check) => check.pattern.test(textForChecks))
    .map((check) => check.label);
  phraseChecks.forEach((check) => {
    if (check.phrases.some((phrase) => textForChecks.includes(phrase))) matches.push(check.label);
  });
  return {
    blocked: matches.length > 0,
    field,
    matches,
    reason: matches.length ? "Human-entered text appears to contain trading advice, live-signal, return-guarantee, copy-trading, or real-money wording." : null,
    constraints: educationComplianceConstraints(),
  };
}

function sendProhibitedAdviceBlock(res, check) {
  sendJson(res, 422, {
    error: "Education compliance guard blocked trading-advice wording",
    complianceGuard: check,
    constraints: check.constraints,
    educationOnly: true,
  });
}

function assessContextDiscipline({ scenario = {}, plan = "" } = {}) {
  const text = String(plan || "");
  const combined = [
    text,
    scenario.news || "",
    scenario.sentiment || "",
  ].join("\n").toLowerCase();
  const planLower = text.toLowerCase();
  const mentionsContext = /(news|headline|event|sentiment|macro|context|background|cpi|fed|earnings|policy|消息|新闻|事件|情绪|宏观|背景|环境|财报|政策)/i.test(text);
  const separatesSignal = /(not a buy|not a sell|not a buy signal|not.*sell signal|not.*signal|background only|context only|not trade|no trade|not advice|not an entry|not an exit|not.*permission to trade|return forecast|learning context|不是.*买|不是.*卖|不是.*信号|不能.*买|不能.*卖|不作为.*信号|只.*背景|只是背景|仅.*背景|不.*交易建议|不是.*依据)/i.test(text);
  const hasRiskPlan = /(invalidation|invalidated|risk|stop|position|wait|confirm|replay|journal|thesis|discipline|失效|风险|止损|仓位|观望|等待|确认|回放|纪律|计划)/i.test(text);
  const emotionalChase = /(because.*sentiment.*buy|because.*news.*buy|headline.*buy|sentiment.*entry|news.*entry|fomo|chase)/i.test(planLower);
  const adviceCheck = prohibitedAdviceCheck(text, { field: "plan" });
  let score = 56;
  if (mentionsContext) score += 14;
  if (separatesSignal) score += 18;
  if (hasRiskPlan) score += 14;
  if (emotionalChase) score -= 24;
  if (adviceCheck.blocked) score -= 30;
  score = Math.max(20, Math.min(96, score));
  const tags = [
    mentionsContext ? "context-aware" : "context-missing",
    separatesSignal ? "sentiment-boundary-clear" : "sentiment-as-signal-risk",
    hasRiskPlan ? "risk-context-linked" : "risk-context-gap",
    emotionalChase ? "headline-chasing-risk" : null,
    adviceCheck.blocked ? "compliance-risk-wording" : null,
  ].filter(Boolean);
  return {
    score,
    mentionsContext,
    separatesSignal,
    hasRiskPlan,
    emotionalChase,
    tags,
    summary: separatesSignal
      ? "消息和情绪被当作学习背景，而不是买卖理由。"
      : "补一句：消息/情绪只是背景，不能变成买卖信号。",
    constraints: [
      "Context review is an education skill score only.",
      "News and sentiment are not live signals, return promises, or real-money trading instructions.",
    ],
    source: {
      newsProvider: scenario.source?.news?.provider || scenario.newsProvider || "demo",
      newsLicense: scenario.source?.news?.license || scenario.newsLicense || "internal-demo-only",
      demoContext: scenario.source?.news?.isDemo !== false,
    },
    educationOnly: true,
  };
}

function createSessionForAccount(db, account) {
  const now = new Date().toISOString();
  const nextToken = crypto.randomBytes(32).toString("hex");
  const nextSession = {
    userId: account.id,
    email: account.email,
    name: account.name,
    role: account.role,
    plan: account.plan,
    loggedInAt: now,
  };
  account.lastLoginAt = now;
  account.updatedAt = now;
  db.sessions[nextToken] = nextSession;
  return { nextToken, nextSession };
}

function adminAccountSummary(db, account) {
  const activeSubscription = activeSubscriptionFor(db, account.id);
  const attempts = (db.attempts || []).filter((item) => item.userId === account.id);
  const replayNotes = (db.replayNotes || []).filter((item) => item.userId === account.id);
  const deletionRequest = (db.deletionRequests || db.auditLogs || []).find((item) => (
    item.type === "account_deletion_requested" &&
    item.userId === account.id &&
    ["needs_review", "processing"].includes(item.moderationStatus)
  ));
  return {
    ...publicAccount(account),
    trainingCount: attempts.length,
    replayNoteCount: replayNotes.length,
    activeSubscription: activeSubscription ? {
      plan: activeSubscription.plan,
      status: activeSubscription.status,
      currentPeriodEnd: activeSubscription.currentPeriodEnd,
    } : null,
    hasOpenDeletionRequest: Boolean(deletionRequest),
  };
}

function auditLogMatches(item, filters) {
  const createdAt = Date.parse(item.createdAt || "");
  if (filters.type && item.type !== filters.type) return false;
  if (filters.userId && item.userId !== filters.userId) return false;
  if (filters.user && ![item.userId, item.email, item.createdBy, item.handledBy]
    .filter(Boolean)
    .some((value) => String(value).toLowerCase().includes(filters.user))) return false;
  if (filters.moderationStatus && item.moderationStatus !== filters.moderationStatus) return false;
  if (filters.from && (!Number.isFinite(createdAt) || createdAt < Date.parse(`${filters.from}T00:00:00.000Z`))) return false;
  if (filters.to && (!Number.isFinite(createdAt) || createdAt > Date.parse(`${filters.to}T23:59:59.999Z`))) return false;
  return true;
}

function auditLogsCsv(items) {
  const columns = ["id", "type", "createdAt", "userId", "email", "moderationStatus", "action", "plan"];
  const escape = (value) => {
    const text = String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  return [
    columns.join(","),
    ...items.map((item) => columns.map((key) => escape(item[key])).join(",")),
  ].join("\n");
}

