function learnerNextStepEngagementMarkdown(report) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  return [
    "# TradeGym Next-Step Engagement Report",
    "",
    `Generated: ${report.generatedAt}`,
    `Events: ${report.summary?.totalEvents || 0}. Opened: ${report.summary?.opened || 0}. Completed: ${report.summary?.completed || 0}. Learners: ${report.summary?.learners || 0}. Action types: ${report.summary?.actionTypes || 0}.`,
    "",
    "## Purpose",
    "This report is for trading-education learner operations. It shows whether learners opened or completed education workflow recommendations. It is not a trading-skill score, win-rate report, return report, market-prediction report, signal report, broker-readiness check, or auto-trading approval.",
    "",
    "## Action Summary",
    "| Action | Opened | Completed | Learners | Latest |",
    "| --- | ---: | ---: | ---: | --- |",
    ...((report.actions || []).map((item) => `| ${line(item.title || item.actionId)} | ${item.opened || 0} | ${item.completed || 0} | ${item.learners || 0} | ${line(item.latestAt)} |`)),
    "",
    "## Recent Events",
    "| Time | Learner | Action | Event | Target |",
    "| --- | --- | --- | --- | --- |",
    ...((report.recentEvents || []).map((item) => `| ${line(item.createdAt)} | ${line(item.email || item.learnerName || item.userId)} | ${line(item.title || item.actionId)} | ${line(item.eventType)} | ${line(item.targetView || "workflow")} |`)),
    "",
    "## Constraints",
    ...((report.constraints || []).map((item) => `- ${line(item)}`)),
    "",
  ].join("\n");
}

function cohortEducationReportCsv(report) {
  const columns = [
    "userId",
    "email",
    "name",
    "completionRate",
    "coursePackageCompletionRate",
    "averageRiskDiscipline",
    "needsCoachReview",
    "recommendedAction",
    "educationOnly",
  ];
  const escape = (value) => {
    const text = Array.isArray(value) ? value.join("|") : String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  return [
    columns.join(","),
    ...(report.memberHighlights || []).map((item) => columns.map((key) => escape(item[key])).join(",")),
  ].join("\n");
}

