function cohortSuccessBrief(db, cohort) {
  const generatedAt = new Date().toISOString();
  const educationReport = buildCohortEducationReport(db, cohort);
  const learningRecords = learningRecordsReport(db, { cohortId: cohort.id, limit: 500 });
  const memberIds = new Set(cohort.memberIds || []);
  const memberEmails = new Set((cohort.memberEmails || []).map((item) => String(item || "").toLowerCase()));
  const rosterHandoffs = (db.rosterImportHandoffs || []).filter((handoff) => (
    handoff.cohort?.id === cohort.id ||
    (handoff.learners || []).some((learner) => memberIds.has(learner.userId) || memberEmails.has(String(learner.email || "").toLowerCase()))
  ));
  const rosterReports = rosterHandoffs.map((handoff) => rosterOnboardingReport(db, handoff));
  const rosterSummary = rosterReports.reduce((summary, report) => ({
    handoffs: summary.handoffs + 1,
    learners: summary.learners + (report.summary?.learners || 0),
    loggedIn: summary.loggedIn + (report.summary?.loggedIn || 0),
    complianceAcknowledged: summary.complianceAcknowledged + (report.summary?.complianceAcknowledged || 0),
    startedTraining: summary.startedTraining + (report.summary?.startedTraining || 0),
    activated: summary.activated + (report.summary?.activated || 0),
    needsAttention: summary.needsAttention + (report.summary?.needsAttention || 0),
  }), {
    handoffs: 0,
    learners: 0,
    loggedIn: 0,
    complianceAcknowledged: 0,
    startedTraining: 0,
    activated: 0,
    needsAttention: 0,
  });
  const activationTasks = (db.activationInterventionTasks || []).filter((task) => (
    memberIds.has(task.userId) ||
    task.cohortId === cohort.id ||
    memberEmails.has(String(task.email || "").toLowerCase())
  ));
  const supportTickets = (db.supportTickets || []).filter((ticket) => (
    memberIds.has(ticket.userId) ||
    memberEmails.has(String(ticket.email || "").toLowerCase())
  ));
  const openActivationTasks = activationTasks.filter((task) => task.status === "open");
  const openSupportTickets = supportTickets.filter((ticket) => !["resolved", "closed", "canceled"].includes(ticket.status));
  const scoreParts = [
    Math.min(25, Math.round((educationReport.summary.practiceCompletionRate || 0) * 0.25)),
    Math.min(20, Math.round((educationReport.summary.packageCompletionRate || 0) * 0.2)),
    Math.min(20, Math.round(((learningRecords.summary?.learners || 0) ? (learningRecords.summary.trainingAttempts || 0) / Math.max(1, learningRecords.summary.learners) : 0) * 8)),
    Math.max(0, 20 - openActivationTasks.length * 4),
    Math.max(0, 15 - openSupportTickets.length * 3),
  ];
  const healthScore = Math.max(0, Math.min(100, scoreParts.reduce((sum, value) => sum + value, 0)));
  const status = healthScore >= 75 ? "healthy" : healthScore >= 50 ? "watch" : "needs_attention";
  const nextCustomerSuccessActions = [
    rosterSummary.needsAttention > 0
      ? `Create or complete onboarding follow-ups for ${rosterSummary.needsAttention} roster learner(s) needing attention.`
      : "Keep roster onboarding in normal weekly monitoring.",
    openActivationTasks.length
      ? `Close ${openActivationTasks.length} open activation follow-up task(s) before the next customer review.`
      : "No open activation follow-up blocker detected for this cohort.",
    educationReport.summary.needsCoachReview > 0
      ? `Assign education-only coach review for ${educationReport.summary.needsCoachReview} learner(s) with risk or invalidation mistakes.`
      : "Use the next cohort session for replay comparison and source-transparency practice.",
    openSupportTickets.length
      ? `Resolve ${openSupportTickets.length} open support ticket(s) before renewal or expansion discussion.`
      : "No open support ticket blocker detected for this cohort.",
  ];
  return {
    schemaVersion: "cohort-success-brief-v1",
    generatedAt,
    cohort: educationReport.cohort,
    healthScore,
    status,
    summary: {
      members: educationReport.cohort.memberCount,
      practiceCompletionRate: educationReport.summary.practiceCompletionRate,
      packageCompletionRate: educationReport.summary.packageCompletionRate,
      learningRecordStatements: learningRecords.summary?.statements || 0,
      trainingAttempts: learningRecords.summary?.trainingAttempts || 0,
      completionReports: learningRecords.summary?.completionReports || 0,
      rosterHandoffs: rosterSummary.handoffs,
      rosterNeedsAttention: rosterSummary.needsAttention,
      openActivationTasks: openActivationTasks.length,
      openSupportTickets: openSupportTickets.length,
      needsCoachReview: educationReport.summary.needsCoachReview,
    },
    sections: {
      educationReport,
      learningRecords: {
        schemaVersion: learningRecords.schemaVersion,
        generatedAt: learningRecords.generatedAt,
        summary: learningRecords.summary,
        learners: (learningRecords.learners || []).slice(0, 12),
        educationOnly: true,
        productionReady: false,
      },
      rosterOnboarding: {
        summary: rosterSummary,
        handoffs: rosterReports.slice(0, 8).map((report) => ({
          handoffId: report.handoffId,
          cohort: report.cohort,
          summary: report.summary,
          nextOpsActions: report.nextOpsActions,
          educationOnly: true,
          productionReady: false,
        })),
        educationOnly: true,
        productionReady: false,
      },
      activationFollowups: {
        open: openActivationTasks.length,
        completed: activationTasks.filter((task) => task.status === "completed").length,
        tasks: activationTasks.slice(0, 20).map((task) => ({
          id: task.id,
          source: task.source,
          email: task.email,
          learnerName: task.learnerName,
          status: task.status,
          currentStepId: task.currentStepId,
          focus: task.focus,
          dueAt: task.dueAt,
          educationOnly: true,
        })),
        educationOnly: true,
        productionReady: false,
      },
      support: {
        openTickets: openSupportTickets.length,
        tickets: supportTickets.slice(0, 20).map((ticket) => ({
          id: ticket.id,
          email: ticket.email,
          category: ticket.category,
          status: ticket.status,
          priority: ticket.priority,
          subject: ticket.subject,
          slaDueAt: ticket.slaDueAt,
          educationOnly: true,
        })),
        educationOnly: true,
        productionReady: false,
      },
    },
    nextCustomerSuccessActions,
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort success briefs are customer-success education operating reports only.",
      "Health score combines learning activity, onboarding, support, and follow-up operations; it does not measure trading performance.",
      "No stock recommendation, live signal, guaranteed return, return promise, broker connection, auto-trading, or real-money trading instruction.",
      "productionReady remains false until production providers, legal review, payment controls, and data governance are independently verified.",
    ],
  };
}

function cohortSuccessBriefCsv(brief) {
  const columns = ["section", "metric", "value", "next", "educationOnly", "productionReady"];
  const escape = (value) => {
    const text = String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  const rows = [
    { section: "cohort", metric: "name", value: brief.cohort?.name || brief.cohort?.id, next: "Use this brief for education customer-success review.", educationOnly: true, productionReady: false },
    { section: "health", metric: "healthScore", value: brief.healthScore, next: brief.status, educationOnly: true, productionReady: false },
    ...Object.entries(brief.summary || {}).map(([metric, value]) => ({ section: "summary", metric, value, next: "", educationOnly: true, productionReady: false })),
    ...((brief.nextCustomerSuccessActions || []).map((next, index) => ({ section: "next_action", metric: `action_${index + 1}`, value: "", next, educationOnly: true, productionReady: false }))),
  ];
  return [
    columns.join(","),
    ...rows.map((row) => columns.map((key) => escape(row[key])).join(",")),
  ].join("\n");
}

