function cohortCompliancePack(db, cohort) {
  const generatedAt = new Date().toISOString();
  const memberIds = cohort.memberIds || [];
  const accounts = memberIds
    .map((userId) => (db.accounts || []).find((account) => account.id === userId))
    .filter(Boolean);
  const openDeletionRequests = (db.deletionRequests || []).filter((item) => (
    item.type === "account_deletion_requested" &&
    ["needs_review", "processing"].includes(item.moderationStatus)
  ));
  const supportTickets = db.supportTickets || [];
  const learners = accounts.map((account) => {
    const compliance = complianceStatusForAccount(account);
    const legalVersionsCurrent = (
      account.termsVersion === legalVersions.terms &&
      account.privacyVersion === legalVersions.privacy &&
      account.riskDisclosureVersion === legalVersions.risk
    );
    const deletionRequest = openDeletionRequests.find((item) => item.userId === account.id);
    const learnerTickets = supportTickets.filter((ticket) => ticket.userId === account.id || ticket.email === account.email);
    const openSupportTickets = learnerTickets.filter((ticket) => !["resolved", "closed", "canceled"].includes(ticket.status));
    const compliant = Boolean(
      account.legalAcceptanceAt &&
      legalVersionsCurrent &&
      compliance.acknowledged &&
      account.emailVerified !== false &&
      !deletionRequest
    );
    const gaps = [
      !account.legalAcceptanceAt ? "missing_legal_acceptance" : null,
      !legalVersionsCurrent ? "outdated_legal_versions" : null,
      !compliance.acknowledged ? "missing_education_risk_acknowledgement" : null,
      account.emailVerified === false ? "email_not_verified" : null,
      deletionRequest ? "open_data_deletion_request" : null,
      openSupportTickets.length ? "open_support_ticket" : null,
    ].filter(Boolean);
    return {
      userId: account.id,
      email: account.email,
      name: account.name,
      accountStatus: account.accountStatus || "active",
      emailVerified: account.emailVerified !== false,
      legalAcceptanceAt: account.legalAcceptanceAt || null,
      legalVersions: {
        terms: account.termsVersion || null,
        privacy: account.privacyVersion || null,
        risk: account.riskDisclosureVersion || null,
        current: legalVersionsCurrent,
      },
      educationRiskAcknowledged: compliance.acknowledged,
      educationRiskAcknowledgedAt: compliance.acknowledgedAt,
      openDeletionRequest: deletionRequest ? {
        id: deletionRequest.id,
        status: deletionRequest.moderationStatus,
        createdAt: deletionRequest.createdAt,
      } : null,
      supportTickets: {
        total: learnerTickets.length,
        open: openSupportTickets.length,
        overdue: openSupportTickets.filter((ticket) => ticket.slaDueAt && Date.parse(ticket.slaDueAt) < Date.now()).length,
      },
      compliant,
      gaps,
      nextComplianceAction: compliant
        ? "Keep normal education boundary monitoring."
        : gaps.includes("missing_legal_acceptance") || gaps.includes("outdated_legal_versions")
          ? "Ask learner to accept current terms, privacy policy, and risk disclosure before training."
          : gaps.includes("missing_education_risk_acknowledgement")
            ? "Ask learner to confirm the education-only risk acknowledgement."
            : gaps.includes("email_not_verified")
              ? "Ask learner to complete email verification in the prototype handoff."
              : gaps.includes("open_data_deletion_request")
                ? "Resolve the learner data deletion request before customer reporting."
                : "Resolve open education-support ticket before customer reporting.",
      educationOnly: true,
      productionReady: false,
    };
  });
  const summary = {
    learners: learners.length,
    compliant: learners.filter((item) => item.compliant).length,
    emailVerified: learners.filter((item) => item.emailVerified).length,
    legalAccepted: learners.filter((item) => item.legalAcceptanceAt).length,
    legalVersionsCurrent: learners.filter((item) => item.legalVersions.current).length,
    educationRiskAcknowledged: learners.filter((item) => item.educationRiskAcknowledged).length,
    openDeletionRequests: learners.filter((item) => item.openDeletionRequest).length,
    openSupportTickets: learners.reduce((sum, item) => sum + item.supportTickets.open, 0),
    gaps: learners.reduce((sum, item) => sum + item.gaps.length, 0),
  };
  const complianceRate = summary.learners ? Math.round((summary.compliant / summary.learners) * 100) : 0;
  return {
    schemaVersion: "cohort-compliance-pack-v1",
    generatedAt,
    cohort: {
      id: cohort.id,
      name: cohort.name,
      status: cohort.status || "active",
      memberCount: memberIds.length,
      educationOnly: true,
    },
    currentLegalVersions: {
      terms: legalVersions.terms,
      privacy: legalVersions.privacy,
      risk: legalVersions.risk,
      educationRisk: complianceVersion,
    },
    summary: {
      ...summary,
      complianceRate,
    },
    learners,
    nextComplianceActions: learners
      .filter((item) => !item.compliant)
      .slice(0, 12)
      .map((item) => `${item.email}: ${item.nextComplianceAction}`),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort compliance packs are institution evidence for education boundaries, legal acceptance, privacy/risk versions, and support operations only.",
      "They do not certify trading skill, trading performance, signal quality, win rate, returns, broker readiness, auto-trading approval, or real-money trading readiness.",
      "No stock recommendation, live signal, guaranteed return, return promise, broker connection, auto-trading, or real-money trading instruction.",
      "productionReady remains false until production identity, legal review, email delivery, data governance, and audit-retention controls are independently verified.",
    ],
  };
}

