function cohortCurriculumSourceEvidence(db, cohort) {
  const memberIds = new Set(cohort.memberIds || []);
  const packageIds = new Set([
    cohort.coursePackageId,
    cohort.lastAssignedCoursePackageId,
    ...(db.coursePackageAssignments || [])
      .filter((assignment) => memberIds.has(assignment.userId) && assignment.status !== "canceled")
      .map((assignment) => assignment.coursePackageId),
    ...(db.courseEnrollments || [])
      .filter((enrollment) => memberIds.has(enrollment.userId) && enrollment.status !== "canceled")
      .map((enrollment) => enrollment.coursePackageId),
  ].filter(Boolean));
  const packages = [...packageIds]
    .map((id) => (db.coursePackages || []).find((item) => item.id === id))
    .filter(Boolean)
    .slice(0, 12)
    .map((coursePackage) => {
      const contentSource = coursePackage.source?.contentSourceId
        ? (db.contentSources || []).find((source) => source.id === coursePackage.source.contentSourceId)
        : null;
      const sourceSummary = contentSource ? contentSourceSummary(contentSource) : null;
      const blockers = [
        !contentSource ? "content_source_missing" : null,
        ...(sourceSummary?.releaseReadiness?.blockers || []),
      ].filter(Boolean);
      return {
        coursePackageId: coursePackage.id,
        coursePackageTitle: coursePackage.title,
        coursePackageStatus: coursePackage.status || "draft",
        releaseChecklist: coursePackage.releaseChecklist || {},
        contentSourceId: contentSource?.id || null,
        contentSourceTitle: contentSource?.title || null,
        sourceType: contentSource?.sourceType || null,
        licenseStatus: sourceSummary?.licenseStatus || "missing",
        reviewStatus: sourceSummary?.reviewStatus || "missing",
        releaseStatus: sourceSummary?.releaseReadiness?.status || "blocked",
        alignmentReviewed: sourceSummary?.releaseReadiness?.alignmentReviewed === true,
        sourceReviewed: sourceSummary?.releaseReadiness?.sourceReviewed === true,
        blockers,
        nextAction: blockers.length
          ? `Close curriculum source evidence blockers: ${blockers.slice(0, 4).join(", ")}.`
          : "Keep curriculum source-rights and alignment evidence attached for institution review.",
        educationOnly: true,
        productionReady: false,
      };
    });
  const blockerCounts = [...new Set(packages.flatMap((item) => item.blockers))].map((key) => ({
    key,
    label: key.replaceAll("_", " "),
    count: packages.filter((item) => item.blockers.includes(key)).length,
  }));
  return {
    schemaVersion: "cohort-curriculum-source-evidence-v1",
    packageCount: packages.length,
    sourceAttached: packages.filter((item) => item.contentSourceId).length,
    readyForDemoAssembly: packages.filter((item) => item.blockers.length === 0).length,
    blockerCount: packages.reduce((sum, item) => sum + item.blockers.length, 0),
    blockerCounts,
    packages,
    nextActions: packages.filter((item) => item.blockers.length).slice(0, 8).map((item) => `${item.coursePackageTitle}: ${item.nextAction}`),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Curriculum source evidence is source-rights, OCR/transcript alignment, and human-review evidence for education content only.",
      "It is not course quality scoring, trading performance evidence, investment advice, live signal quality, broker readiness, auto-trading approval, or real-money trading readiness.",
    ],
  };
}

function cohortProcurementPacket(db, cohort) {
  const successBrief = cohortSuccessBrief(db, cohort);
  const compliancePack = cohortCompliancePack(db, cohort);
  const curriculumSourceEvidence = cohortCurriculumSourceEvidence(db, cohort);
  const serviceSlaActionRollup = cohortServiceSlaActionRollup(db, cohort);
  const success = successBrief.summary || {};
  const compliance = compliancePack.summary || {};
  const serviceActionsNeedingFollowup = (serviceSlaActionRollup.open || 0) + (serviceSlaActionRollup.inProgress || 0);
  const blockers = [
    compliance.gaps > 0 ? `${compliance.gaps} compliance evidence gap(s)` : null,
    success.openSupportTickets > 0 ? `${success.openSupportTickets} open support ticket(s)` : null,
    serviceActionsNeedingFollowup > 0 ? `${serviceActionsNeedingFollowup} service SLA action(s) need owner follow-through` : null,
    success.openActivationTasks > 0 ? `${success.openActivationTasks} open activation follow-up task(s)` : null,
    success.needsCoachReview > 0 ? `${success.needsCoachReview} learner(s) need education-only coach review` : null,
    success.rosterNeedsAttention > 0 ? `${success.rosterNeedsAttention} roster learner(s) need onboarding attention` : null,
    curriculumSourceEvidence.blockerCount > 0 ? `${curriculumSourceEvidence.blockerCount} curriculum source evidence blocker(s)` : null,
  ].filter(Boolean);
  const readiness = blockers.length
    ? "procurement_review_gaps"
    : successBrief.status === "healthy" && compliance.complianceRate >= 90
      ? "education_procurement_packet_ready"
      : "education_procurement_watch";
  const executiveSummary = [
    `Cohort health ${successBrief.healthScore}/100 (${successBrief.status}).`,
    `Compliance evidence ${compliance.complianceRate || 0}% complete.`,
    `Learning evidence includes ${success.learningRecordStatements || 0} statement(s), ${success.trainingAttempts || 0} training attempt(s), and ${success.completionReports || 0} completion report(s).`,
    `Service follow-through includes ${serviceSlaActionRollup.totalActions || 0} SLA action(s), ${serviceActionsNeedingFollowup} still open or in progress, and ${serviceSlaActionRollup.done || 0} done.`,
    blockers.length
      ? `Procurement review should close: ${blockers.slice(0, 4).join("; ")}.`
      : "No current cohort-level procurement evidence blocker is detected in the prototype.",
  ];
  const blockerCategories = cohortProcurementBlockerCategories({
    complianceGaps: compliance.gaps || 0,
    openSupportTickets: success.openSupportTickets || 0,
    serviceSlaActionsOpen: serviceSlaActionRollup.open || 0,
    serviceSlaActionsInProgress: serviceSlaActionRollup.inProgress || 0,
    serviceSlaActionsDone: serviceSlaActionRollup.done || 0,
    openActivationTasks: success.openActivationTasks || 0,
    needsCoachReview: success.needsCoachReview || 0,
    rosterNeedsAttention: success.rosterNeedsAttention || 0,
    learningRecordStatements: success.learningRecordStatements || 0,
    completionReports: success.completionReports || 0,
    curriculumSourceBlockers: curriculumSourceEvidence.blockerCount,
  });
  return {
    schemaVersion: "cohort-procurement-packet-v1",
    generatedAt: new Date().toISOString(),
    cohort: successBrief.cohort,
    readiness,
    summary: {
      members: success.members || 0,
      healthScore: successBrief.healthScore,
      healthStatus: successBrief.status,
      practiceCompletionRate: success.practiceCompletionRate || 0,
      packageCompletionRate: success.packageCompletionRate || 0,
      learningRecordStatements: success.learningRecordStatements || 0,
      trainingAttempts: success.trainingAttempts || 0,
      completionReports: success.completionReports || 0,
      complianceRate: compliance.complianceRate || 0,
      complianceGaps: compliance.gaps || 0,
      openSupportTickets: success.openSupportTickets || 0,
      serviceSlaActionsOpen: serviceSlaActionRollup.open || 0,
      serviceSlaActionsInProgress: serviceSlaActionRollup.inProgress || 0,
      serviceSlaActionsDone: serviceSlaActionRollup.done || 0,
      openActivationTasks: success.openActivationTasks || 0,
      rosterNeedsAttention: success.rosterNeedsAttention || 0,
      needsCoachReview: success.needsCoachReview || 0,
      curriculumPackages: curriculumSourceEvidence.packageCount,
      curriculumSourcesAttached: curriculumSourceEvidence.sourceAttached,
      curriculumSourceBlockers: curriculumSourceEvidence.blockerCount,
      blockers: blockers.length,
    },
    executiveSummary,
    blockers,
    blockerCategories,
    customerSuccessActions: [
      ...(successBrief.nextCustomerSuccessActions || []),
      ...(compliancePack.nextComplianceActions || []),
    ].slice(0, 12),
    evidence: {
      successBrief: {
        schemaVersion: successBrief.schemaVersion,
        healthScore: successBrief.healthScore,
        status: successBrief.status,
        summary: successBrief.summary,
        nextCustomerSuccessActions: successBrief.nextCustomerSuccessActions,
        educationOnly: true,
        productionReady: false,
      },
      compliancePack: {
        schemaVersion: compliancePack.schemaVersion,
        summary: compliancePack.summary,
        nextComplianceActions: compliancePack.nextComplianceActions,
        currentLegalVersions: compliancePack.currentLegalVersions,
        learnerSample: (compliancePack.learners || []).slice(0, 12),
        educationOnly: true,
        productionReady: false,
      },
      curriculumSourceEvidence,
      serviceSlaActionRollup,
    },
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort procurement packets combine education adoption, onboarding, support, legal acceptance, risk acknowledgement, and data-rights evidence for institution review.",
      "This packet is for education SaaS procurement, renewal, and customer-success review only.",
      "It is not investment advice, trading-performance evidence, signal quality evidence, win-rate evidence, return evidence, broker readiness, auto-trading approval, or real-money trading readiness.",
      "No stock recommendation, live signal, guaranteed return, return promise, broker connection, auto-trading, or real-money trading instruction.",
      "productionReady remains false until production providers, legal review, payment controls, data governance, and audit retention are independently verified.",
    ],
  };
}

function cohortProcurementBlockerCategories(summary = {}, { providerMode = "" } = {}) {
  const categories = [
    {
      key: "compliance_evidence",
      label: "Compliance evidence",
      count: summary.complianceGaps || 0,
      status: (summary.complianceGaps || 0) > 0 ? "blocked" : "ready",
      evidence: `${summary.complianceGaps || 0} legal, risk, privacy, or data-rights evidence gap(s)`,
      next: (summary.complianceGaps || 0) > 0
        ? "Close education-risk, legal acceptance, privacy, and data-rights evidence before institution procurement review."
        : "Keep compliance evidence current for procurement review.",
    },
    {
      key: "support_sla",
      label: "Support follow-through",
      count: (summary.openSupportTickets || 0) + (summary.serviceSlaActionsOpen || 0) + (summary.serviceSlaActionsInProgress || 0),
      status: ((summary.openSupportTickets || 0) + (summary.serviceSlaActionsOpen || 0) + (summary.serviceSlaActionsInProgress || 0)) > 0 ? "needs_action" : "ready",
      evidence: `${summary.openSupportTickets || 0} open support ticket(s), ${summary.serviceSlaActionsOpen || 0} open service SLA action(s), ${summary.serviceSlaActionsInProgress || 0} in progress, ${summary.serviceSlaActionsDone || 0} done`,
      next: ((summary.openSupportTickets || 0) + (summary.serviceSlaActionsOpen || 0) + (summary.serviceSlaActionsInProgress || 0)) > 0
        ? "Resolve learner support tickets and close education service SLA actions before presenting procurement readiness."
        : "No open support blocker detected for this cohort.",
    },
    {
      key: "activation_followup",
      label: "Activation follow-up",
      count: summary.openActivationTasks || 0,
      status: (summary.openActivationTasks || 0) > 0 ? "needs_action" : "ready",
      evidence: `${summary.openActivationTasks || 0} open activation task(s)`,
      next: (summary.openActivationTasks || 0) > 0
        ? "Complete onboarding and activation customer-success follow-ups before renewal review."
        : "Activation follow-through is not currently blocking the procurement packet.",
    },
    {
      key: "coach_follow_through",
      label: "Coach follow-through",
      count: summary.needsCoachReview || 0,
      status: (summary.needsCoachReview || 0) > 0 ? "needs_action" : "ready",
      evidence: `${summary.needsCoachReview || 0} learner(s) need education-only coach review`,
      next: (summary.needsCoachReview || 0) > 0
        ? "Assign human coach review for education evidence gaps; do not frame it as trading-skill certification."
        : "Coach follow-through is not currently blocking the cohort packet.",
    },
    {
      key: "roster_onboarding",
      label: "Roster onboarding",
      count: summary.rosterNeedsAttention || 0,
      status: (summary.rosterNeedsAttention || 0) > 0 ? "needs_action" : "ready",
      evidence: `${summary.rosterNeedsAttention || 0} roster learner(s) need onboarding attention`,
      next: (summary.rosterNeedsAttention || 0) > 0
        ? "Finish roster onboarding before institution procurement or renewal review."
        : "Roster onboarding is not currently blocking this cohort.",
    },
    {
      key: "learning_evidence",
      label: "Learning evidence",
      count: (summary.learningRecordStatements || 0) + (summary.completionReports || 0),
      status: (summary.learningRecordStatements || 0) || (summary.completionReports || 0) ? "ready" : "watch",
      evidence: `${summary.learningRecordStatements || 0} learning statement(s), ${summary.completionReports || 0} completion report(s)`,
      next: (summary.learningRecordStatements || 0) || (summary.completionReports || 0)
        ? "Use learning evidence as education adoption proof only, not trading performance evidence."
        : "Collect more education adoption evidence before procurement review.",
    },
    {
      key: "curriculum_source_evidence",
      label: "Curriculum source evidence",
      count: summary.curriculumSourceBlockers || 0,
      status: (summary.curriculumSourceBlockers || 0) > 0 ? "needs_action" : "ready",
      evidence: `${summary.curriculumSourceBlockers || 0} source-rights, OCR/transcript alignment, or content review blocker(s)`,
      next: (summary.curriculumSourceBlockers || 0) > 0
        ? "Attach curriculum source release evidence before presenting paid course content as procurement-ready."
        : "Curriculum source evidence is not currently blocking the cohort packet.",
    },
  ];
  if (providerMode) {
    categories.push({
      key: "provider_readiness",
      label: "Provider readiness",
      count: providerMode === "local-simulated" ? 1 : 0,
      status: providerMode === "local-simulated" ? "prototype_only" : "ready",
      evidence: `Email provider mode: ${providerMode}`,
      next: providerMode === "local-simulated"
        ? "Replace local simulated delivery with production email provider evidence before claiming production delivery."
        : "Keep provider delivery evidence attached to institution procurement records.",
    });
  }
  return categories.map((item) => ({
    ...item,
    category: item.key,
    severity: item.status === "blocked" ? "high" : item.status === "needs_action" || item.status === "prototype_only" ? "medium" : "low",
    nextCustomerSuccessAction: item.next,
    educationOnly: true,
    productionReady: false,
  }));
}

function cohortProcurementPacketCsv(packet) {
  const columns = ["section", "metric", "value", "next", "educationOnly", "productionReady"];
  const escape = (value) => {
    const text = Array.isArray(value) ? value.join("|") : String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  const rows = [
    { section: "cohort", metric: "name", value: packet.cohort?.name || packet.cohort?.id, next: packet.readiness, educationOnly: true, productionReady: false },
    ...Object.entries(packet.summary || {}).map(([metric, value]) => ({ section: "summary", metric, value, next: "", educationOnly: true, productionReady: false })),
    ...((packet.blockers || []).map((item, index) => ({ section: "blocker", metric: `blocker_${index + 1}`, value: item, next: "Close before procurement or renewal review.", educationOnly: true, productionReady: false }))),
    ...((packet.blockerCategories || []).map((item) => ({ section: "blocker_category", metric: item.category || item.key, value: `${item.status}:${item.count || 0}`, next: item.nextCustomerSuccessAction || item.next || "", educationOnly: true, productionReady: false }))),
    ...((packet.evidence?.curriculumSourceEvidence?.packages || []).map((item) => ({ section: "curriculum_source", metric: item.coursePackageId, value: `${item.contentSourceId || "missing"}:${item.releaseStatus}:${(item.blockers || []).join("|") || "none"}`, next: item.nextAction || "", educationOnly: true, productionReady: false }))),
    ...((packet.customerSuccessActions || []).map((next, index) => ({ section: "next_action", metric: `action_${index + 1}`, value: "", next, educationOnly: true, productionReady: false }))),
  ];
  return [
    columns.join(","),
    ...rows.map((row) => columns.map((key) => escape(row[key])).join(",")),
  ].join("\n");
}

function cohortProcurementPacketMarkdown(packet) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  const summary = packet.summary || {};
  return [
    "# TradeGym Cohort Procurement Packet",
    "",
    `Generated: ${line(packet.generatedAt)}`,
    `Cohort: ${line(packet.cohort?.name || packet.cohort?.id)}`,
    `Readiness: ${line(packet.readiness)}`,
    `Production ready: ${packet.productionReady}. Education only: ${packet.educationOnly}.`,
    "",
    "## Executive Summary",
    ...((packet.executiveSummary || []).map((item) => `- ${line(item)}`)),
    "",
    "## Evidence Summary",
    `Members: ${summary.members || 0}. Health: ${summary.healthScore || 0}/100 (${line(summary.healthStatus)}). Practice completion: ${summary.practiceCompletionRate || 0}%. Package completion: ${summary.packageCompletionRate || 0}%.`,
    `Learning statements: ${summary.learningRecordStatements || 0}. Training attempts: ${summary.trainingAttempts || 0}. Completion reports: ${summary.completionReports || 0}.`,
    `Compliance rate: ${summary.complianceRate || 0}%. Compliance gaps: ${summary.complianceGaps || 0}. Support tickets: ${summary.openSupportTickets || 0}. Activation follow-ups: ${summary.openActivationTasks || 0}.`,
    `Service SLA actions: open ${summary.serviceSlaActionsOpen || 0}, in progress ${summary.serviceSlaActionsInProgress || 0}, done ${summary.serviceSlaActionsDone || 0}.`,
    `Curriculum packages: ${summary.curriculumPackages || 0}. Sources attached: ${summary.curriculumSourcesAttached || 0}. Source blockers: ${summary.curriculumSourceBlockers || 0}.`,
    "",
    "## Procurement Blockers",
    ...((packet.blockers || []).length ? packet.blockers.map((item) => `- ${line(item)}`) : ["- No current cohort-level procurement evidence blocker detected in the prototype."]),
    "",
    "## Blocker Categories",
    "| Category | Status | Count | Next |",
    "| --- | --- | ---: | --- |",
    ...((packet.blockerCategories || []).map((item) => `| ${line(item.label || item.category || item.key)} | ${line(item.status)} | ${item.count || 0} | ${line(item.nextCustomerSuccessAction || item.next)} |`)),
    "",
    "## Curriculum Source Evidence",
    "| Package | Source | Release | Blockers | Next |",
    "| --- | --- | --- | --- | --- |",
    ...((packet.evidence?.curriculumSourceEvidence?.packages || []).map((item) => `| ${line(item.coursePackageTitle)} | ${line(item.contentSourceTitle || item.contentSourceId || "missing")} | ${line(item.releaseStatus)} | ${line((item.blockers || []).join(", ") || "none")} | ${line(item.nextAction)} |`)),
    ...((packet.evidence?.curriculumSourceEvidence?.packages || []).length ? [] : ["| No course package source evidence yet | missing | blocked | content_source_missing | Attach content source release evidence before procurement review. |"]),
    "",
    "## Customer Success Actions",
    ...((packet.customerSuccessActions || []).map((item) => `- ${line(item)}`)),
    "",
    "## Boundaries",
    ...((packet.constraints || []).map((item) => `- ${line(item)}`)),
    "",
  ].join("\n");
}

function cohortProcurementDeliveryQueue(db, { q = "", cohortId = "" } = {}) {
  const query = String(q || "").trim().toLowerCase();
  const targetCohortId = String(cohortId || "").trim();
  const deliveries = (db.cohortProcurementDeliveries || [])
    .filter((item) => !targetCohortId || item.cohortId === targetCohortId)
    .filter((item) => !query || [
      item.cohortName,
      item.recipientEmail,
      item.ownerEmail,
      item.status,
      item.readiness,
      item.feedbackStatus,
      item.cohortId,
    ].filter(Boolean).some((value) => String(value).toLowerCase().includes(query)))
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0));
  return {
    generatedAt: new Date().toISOString(),
    educationOnly: true,
    productionReady: false,
    deliveries: deliveries.slice(0, 50),
    summary: {
      total: deliveries.length,
      sent: deliveries.filter((item) => item.status === "sent").length,
      feedbackPending: deliveries.filter((item) => item.feedbackStatus === "pending_feedback" || !item.feedbackStatus).length,
      procurementReady: deliveries.filter((item) => item.feedbackStatus === "procurement_ready").length,
      objections: deliveries.filter((item) => item.feedbackStatus === "objections").length,
      needsMoreEvidence: deliveries.filter((item) => item.feedbackStatus === "needs_more_evidence").length,
      noFit: deliveries.filter((item) => item.feedbackStatus === "no_fit").length,
      localSimulated: deliveries.filter((item) => item.providerMode === "local-simulated").length,
      external: deliveries.filter((item) => item.providerMode === "external").length,
    },
    provider: emailProvider.providerStatus(),
    constraints: [
      "Cohort procurement deliveries are institution customer-success handoff records only.",
      "Local provider mode is simulated and does not prove production email delivery.",
      "Procurement deliveries do not provide stock recommendations, live signals, return promises, broker connectivity, auto-trading, or real-money trading instructions.",
    ],
  };
}

function cohortProcurementProgressReport(db, { q = "", cohortId = "" } = {}) {
  const queue = cohortProcurementDeliveryQueue(db, { q, cohortId });
  const actions = db.pilotSuccessActions || [];
  const cohort = cohortId ? (db.cohorts || []).find((item) => item.id === String(cohortId || "")) : null;
  const serviceSlaActionRollup = cohort ? cohortServiceSlaActionRollup(db, cohort) : null;
  const deliveries = (queue.deliveries || []).map((delivery) => {
    const linkedAction = delivery.nextActionId
      ? actions.find((item) => item.id === delivery.nextActionId) || null
      : actions.find((item) => item.deliveryId === delivery.id && String(item.sourceKey || "").startsWith("cohort_procurement_feedback:")) || null;
    const actionStatus = delivery.nextActionStatus || linkedAction?.status || null;
    const status = delivery.feedbackStatus === "pending_feedback" || !delivery.feedbackStatus
      ? "waiting_for_institution_feedback"
      : actionStatus && ["done", "deferred"].includes(actionStatus)
        ? `feedback_action_${actionStatus}`
        : actionStatus
          ? `feedback_action_${actionStatus}`
          : "feedback_needs_action";
    const nextCustomerSuccessAction = actionStatus === "done"
      ? "Keep resolution evidence in the procurement record and prepare education-only renewal or procurement review."
      : actionStatus === "deferred"
        ? "Revisit the deferred education customer-success action before institution procurement review."
        : delivery.nextCustomerSuccessAction || "Collect institution feedback on the education procurement packet.";
    return {
      id: delivery.id,
      cohortId: delivery.cohortId,
      cohortName: delivery.cohortName,
      recipientEmail: delivery.recipientEmail,
      ownerEmail: delivery.ownerEmail,
      readiness: delivery.readiness,
      status,
      feedbackStatus: delivery.feedbackStatus || "pending_feedback",
      providerMode: delivery.providerMode,
      sentAt: delivery.sentAt,
      feedbackAt: delivery.feedbackAt,
      blockerCount: delivery.blockerCount || 0,
      blockerCategories: cohortProcurementBlockerCategories({
        complianceGaps: delivery.packetSummary?.complianceGaps || 0,
        openSupportTickets: delivery.packetSummary?.openSupportTickets || 0,
        serviceSlaActionsOpen: delivery.packetSummary?.serviceSlaActionsOpen || 0,
        serviceSlaActionsInProgress: delivery.packetSummary?.serviceSlaActionsInProgress || 0,
        serviceSlaActionsDone: delivery.packetSummary?.serviceSlaActionsDone || 0,
        openActivationTasks: delivery.packetSummary?.openActivationTasks || 0,
        needsCoachReview: delivery.packetSummary?.needsCoachReview || 0,
        rosterNeedsAttention: delivery.packetSummary?.rosterNeedsAttention || 0,
        learningRecordStatements: delivery.packetSummary?.learningRecordStatements || 0,
        completionReports: delivery.packetSummary?.completionReports || 0,
      }, { providerMode: delivery.providerMode || "" }),
      institutionOwnerEmail: delivery.institutionOwnerEmail || delivery.recipientEmail || null,
      targetReviewAt: delivery.targetReviewAt || null,
      decisionNote: delivery.decisionNote || "",
      nextCustomerSuccessAction,
      nextActionId: delivery.nextActionId || linkedAction?.id || null,
      nextActionStatus: actionStatus,
      nextActionOwnerEmail: linkedAction?.ownerEmail || null,
      nextActionPriority: linkedAction?.priority || null,
      nextActionUpdatedAt: delivery.nextActionUpdatedAt || linkedAction?.updatedAt || null,
      nextActionResolutionNote: delivery.nextActionResolutionNote || linkedAction?.resolutionNote || "",
      educationOnly: true,
      productionReady: false,
    };
  });
  const blockerCategoryCounts = deliveries.reduce((counts, delivery) => {
    (delivery.blockerCategories || []).forEach((category) => {
      const key = category.category || category.key;
      if (!key) return;
      counts[key] ||= { key, label: category.label || key, total: 0, blocked: 0, needsAction: 0, prototypeOnly: 0 };
      counts[key].total += 1;
      if (category.status === "blocked") counts[key].blocked += 1;
      if (category.status === "needs_action") counts[key].needsAction += 1;
      if (category.status === "prototype_only") counts[key].prototypeOnly += 1;
    });
    return counts;
  }, {});
  const blockerCategorySummary = Object.values(blockerCategoryCounts)
    .sort((a, b) => (b.blocked + b.needsAction + b.prototypeOnly) - (a.blocked + a.needsAction + a.prototypeOnly) || b.total - a.total);
  deliveries.forEach((delivery) => {
    const dominant = (delivery.blockerCategories || [])
      .filter((item) => ["blocked", "needs_action", "prototype_only", "watch"].includes(item.status))
      .sort((a, b) => (a.severity === "high" ? -1 : b.severity === "high" ? 1 : 0))[0] || (delivery.blockerCategories || [])[0] || null;
    delivery.dominantBlockerCategory = dominant?.category || dominant?.key || null;
    delivery.dominantBlockerLabel = dominant?.label || null;
  });
  const summary = {
    ...queue.summary,
    feedbackActionsOpen: deliveries.filter((item) => item.nextActionStatus === "open").length,
    feedbackActionsInProgress: deliveries.filter((item) => item.nextActionStatus === "in_progress").length,
    feedbackActionsDone: deliveries.filter((item) => item.nextActionStatus === "done").length,
    feedbackActionsDeferred: deliveries.filter((item) => item.nextActionStatus === "deferred").length,
    feedbackNeedsAction: deliveries.filter((item) => item.status === "feedback_needs_action").length,
    waitingForFeedback: deliveries.filter((item) => item.status === "waiting_for_institution_feedback").length,
    blockerCategoryCounts: blockerCategorySummary,
    institutionCsActionRollup: institutionCsActionRollup(actions, deliveries),
    serviceSlaActionRollup,
  };
  return {
    schemaVersion: "cohort-procurement-progress-v1",
    generatedAt: queue.generatedAt,
    summary,
    deliveries,
    provider: queue.provider,
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort procurement progress is an institution customer-success operating report for education SaaS only.",
      "It tracks packet handoff, institution feedback, and follow-through actions; it is not trading performance, signal quality, win-rate, return, broker, auto-trading, or real-money readiness evidence.",
      "Local provider mode remains simulated and does not prove production email delivery.",
      "productionReady remains false until production identity, delivery, legal, payment, data governance, and audit-retention controls are independently verified.",
    ],
  };
}

function institutionCsActionRollup(actions = [], deliveries = []) {
  const deliveryById = new Map(deliveries.map((delivery) => [delivery.id, delivery]));
  const relevantActions = (actions || []).filter((action) => (
    String(action.sourceKey || "").startsWith("cohort_procurement_feedback:") ||
    action.cohortId ||
    action.deliveryId ||
    action.criterionKey
  ));
  const statuses = ["open", "in_progress", "done", "deferred"];
  const bump = (row, action) => {
    const status = statuses.includes(action.status) ? action.status : "open";
    row.total += 1;
    row[status === "in_progress" ? "inProgress" : status] += 1;
    if (action.priority === "high") row.high += 1;
    if (action.priority === "medium") row.medium += 1;
  };
  const byCohort = new Map();
  const byOwner = new Map();
  const byPriority = new Map();
  const byBlockerCategory = new Map();

  relevantActions.forEach((action) => {
    const delivery = action.deliveryId ? deliveryById.get(action.deliveryId) : null;
    const cohortKey = action.cohortId || delivery?.cohortId || "product_readiness";
    const cohortRow = byCohort.get(cohortKey) || {
      cohortId: cohortKey,
      cohortName: delivery?.cohortName || (cohortKey === "product_readiness" ? "Product readiness" : cohortKey),
      total: 0,
      open: 0,
      inProgress: 0,
      done: 0,
      deferred: 0,
      high: 0,
      medium: 0,
      blockers: [],
      educationOnly: true,
      productionReady: false,
    };
    bump(cohortRow, action);
    (delivery?.blockerCategories || []).forEach((category) => {
      const key = category.category || category.key;
      if (key && !cohortRow.blockers.includes(key)) cohortRow.blockers.push(key);
    });
    byCohort.set(cohortKey, cohortRow);

    const ownerKey = action.ownerEmail || delivery?.ownerEmail || "unassigned";
    const ownerRow = byOwner.get(ownerKey) || {
      ownerEmail: ownerKey,
      total: 0,
      open: 0,
      inProgress: 0,
      done: 0,
      deferred: 0,
      high: 0,
      medium: 0,
      educationOnly: true,
      productionReady: false,
    };
    bump(ownerRow, action);
    byOwner.set(ownerKey, ownerRow);

    const priorityKey = action.priority || "medium";
    const priorityRow = byPriority.get(priorityKey) || {
      priority: priorityKey,
      total: 0,
      open: 0,
      inProgress: 0,
      done: 0,
      deferred: 0,
      educationOnly: true,
      productionReady: false,
    };
    const status = statuses.includes(action.status) ? action.status : "open";
    priorityRow.total += 1;
    priorityRow[status === "in_progress" ? "inProgress" : status] += 1;
    byPriority.set(priorityKey, priorityRow);

    const categories = delivery?.blockerCategories?.length
      ? delivery.blockerCategories
      : [{ category: "unlinked_action", key: "unlinked_action", label: "Unlinked action" }];
    categories.forEach((category) => {
      const categoryKey = category.category || category.key;
      if (!categoryKey) return;
      const categoryRow = byBlockerCategory.get(categoryKey) || {
        category: categoryKey,
        label: category.label || categoryKey,
        totalActions: 0,
        open: 0,
        inProgress: 0,
        done: 0,
        deferred: 0,
        high: 0,
        cohorts: [],
        educationOnly: true,
        productionReady: false,
      };
      const actionStatus = statuses.includes(action.status) ? action.status : "open";
      categoryRow.totalActions += 1;
      categoryRow[actionStatus === "in_progress" ? "inProgress" : actionStatus] += 1;
      if (action.priority === "high") categoryRow.high += 1;
      if (delivery?.cohortId && !categoryRow.cohorts.includes(delivery.cohortId)) categoryRow.cohorts.push(delivery.cohortId);
      byBlockerCategory.set(categoryKey, categoryRow);
    });
  });

  const sortRows = (rows) => rows.sort((a, b) => (b.open + b.inProgress + b.high) - (a.open + a.inProgress + a.high) || b.total - a.total);
  return {
    totalActions: relevantActions.length,
    open: relevantActions.filter((item) => (item.status || "open") === "open").length,
    inProgress: relevantActions.filter((item) => item.status === "in_progress").length,
    done: relevantActions.filter((item) => item.status === "done").length,
    deferred: relevantActions.filter((item) => item.status === "deferred").length,
    high: relevantActions.filter((item) => item.priority === "high").length,
    byCohort: sortRows([...byCohort.values()]),
    byOwner: sortRows([...byOwner.values()]),
    byPriority: [...byPriority.values()].sort((a, b) => b.total - a.total),
    byBlockerCategory: [...byBlockerCategory.values()].sort((a, b) => (b.open + b.inProgress + b.high) - (a.open + a.inProgress + a.high) || b.totalActions - a.totalActions),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Institution CS action rollup is a customer-success operations summary only.",
      "It is not a success rate, trading-performance score, live signal quality measure, broker readiness signal, auto-trading approval, or real-money readiness indicator.",
    ],
  };
}

function cohortServiceSlaActionRollup(db, cohort) {
  const memberIds = new Set(cohort?.memberIds || []);
  const memberEmails = new Set((cohort?.memberEmails || []).map((item) => String(item || "").toLowerCase()));
  const actions = (db.pilotSuccessActions || []).filter((action) => {
    if (!String(action.sourceKey || "").startsWith("service_sla:")) return false;
    const actionEmail = String(action.q || action.email || "").toLowerCase();
    return memberIds.has(action.userId) || (actionEmail && memberEmails.has(actionEmail));
  });
  const statuses = ["open", "in_progress", "done", "deferred"];
  const summary = {
    totalActions: actions.length,
    open: actions.filter((item) => (item.status || "open") === "open").length,
    inProgress: actions.filter((item) => item.status === "in_progress").length,
    done: actions.filter((item) => item.status === "done").length,
    deferred: actions.filter((item) => item.status === "deferred").length,
    high: actions.filter((item) => item.priority === "high").length,
    educationOnly: true,
    productionReady: false,
  };
  const byOwner = new Map();
  const byType = new Map();
  actions.forEach((action) => {
    const status = statuses.includes(action.status) ? action.status : "open";
    const ownerKey = action.ownerEmail || "unassigned";
    const ownerRow = byOwner.get(ownerKey) || { ownerEmail: ownerKey, total: 0, open: 0, inProgress: 0, done: 0, deferred: 0, high: 0, educationOnly: true, productionReady: false };
    ownerRow.total += 1;
    ownerRow[status === "in_progress" ? "inProgress" : status] += 1;
    if (action.priority === "high") ownerRow.high += 1;
    byOwner.set(ownerKey, ownerRow);

    const typeKey = action.serviceItemType || action.blockerCategory || "service_sla";
    const typeRow = byType.get(typeKey) || { type: typeKey, total: 0, open: 0, inProgress: 0, done: 0, deferred: 0, high: 0, educationOnly: true, productionReady: false };
    typeRow.total += 1;
    typeRow[status === "in_progress" ? "inProgress" : status] += 1;
    if (action.priority === "high") typeRow.high += 1;
    byType.set(typeKey, typeRow);
  });
  return {
    ...summary,
    byOwner: [...byOwner.values()].sort((a, b) => (b.open + b.inProgress + b.high) - (a.open + a.inProgress + a.high) || b.total - a.total),
    byType: [...byType.values()].sort((a, b) => (b.open + b.inProgress + b.high) - (a.open + a.inProgress + a.high) || b.total - a.total),
    actions: actions.slice(0, 12).map((action) => ({
      id: action.id,
      sourceKey: action.sourceKey,
      title: action.title,
      status: action.status || "open",
      priority: action.priority || "medium",
      ownerEmail: action.ownerEmail || null,
      serviceItemType: action.serviceItemType || null,
      blockerCategory: action.blockerCategory || "service_sla",
      next: action.next || "",
      updatedAt: action.updatedAt || action.createdAt,
      educationOnly: true,
      productionReady: false,
    })),
    constraints: [
      "Cohort service SLA action rollup tracks education support and delivery follow-through only.",
      "It is not investment advice, trading-performance evidence, live signal quality, broker readiness, auto-trading approval, or real-money readiness.",
    ],
  };
}

function cohortProcurementProgressCsv(report) {
  const columns = [
    "cohortName",
    "recipientEmail",
    "readiness",
    "status",
    "dominantBlockerCategory",
    "dominantBlockerLabel",
    "blockerCategories",
    "feedbackStatus",
    "nextActionStatus",
    "ownerEmail",
    "institutionOwnerEmail",
    "targetReviewAt",
    "decisionNote",
    "providerMode",
    "nextCustomerSuccessAction",
    "educationOnly",
    "productionReady",
  ];
  const escape = (value) => {
    const text = Array.isArray(value) ? value.join("|") : String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  const rows = (report.deliveries || []).map((row) => ({
    ...row,
    blockerCategories: (row.blockerCategories || []).map((item) => `${item.category || item.key}:${item.status}:${item.count}`).join("|"),
  }));
  return [
    columns.join(","),
    ...rows.map((row) => columns.map((key) => escape(row[key])).join(",")),
  ].join("\n");
}

function cohortProcurementProgressMarkdown(report) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  const summary = report.summary || {};
  return [
    "# TradeGym Cohort Procurement Progress",
    "",
    `Generated: ${line(report.generatedAt)}`,
    `Production ready: ${report.productionReady}. Education only: ${report.educationOnly}.`,
    "",
    "## Summary",
    `Deliveries: ${summary.total || 0}. Waiting feedback: ${summary.waitingForFeedback || 0}. Needs action: ${summary.feedbackNeedsAction || 0}. Ready: ${summary.procurementReady || 0}. Objections: ${summary.objections || 0}. More evidence: ${summary.needsMoreEvidence || 0}.`,
    `Actions open: ${summary.feedbackActionsOpen || 0}. In progress: ${summary.feedbackActionsInProgress || 0}. Done: ${summary.feedbackActionsDone || 0}. Deferred: ${summary.feedbackActionsDeferred || 0}. Local simulated: ${summary.localSimulated || 0}.`,
    "",
    "## Blocker Categories",
    "| Category | Total | Blocked | Needs action | Prototype only |",
    "| --- | ---: | ---: | ---: | ---: |",
    ...((summary.blockerCategoryCounts || []).map((item) => `| ${line(item.label || item.key)} | ${item.total || 0} | ${item.blocked || 0} | ${item.needsAction || 0} | ${item.prototypeOnly || 0} |`)),
    "",
    "## Institution CS Action Rollup",
    `Actions: ${summary.institutionCsActionRollup?.totalActions || 0}. Open: ${summary.institutionCsActionRollup?.open || 0}. In progress: ${summary.institutionCsActionRollup?.inProgress || 0}. Done: ${summary.institutionCsActionRollup?.done || 0}. High priority: ${summary.institutionCsActionRollup?.high || 0}.`,
    "| Owner | Open | In progress | Done | High |",
    "| --- | ---: | ---: | ---: | ---: |",
    ...((summary.institutionCsActionRollup?.byOwner || []).slice(0, 8).map((item) => `| ${line(item.ownerEmail)} | ${item.open || 0} | ${item.inProgress || 0} | ${item.done || 0} | ${item.high || 0} |`)),
    "",
    "## Delivery Follow-through",
    "| Cohort | Main blocker | Institution owner | Target review | Feedback | Action | Next |",
    "| --- | --- | --- | --- | --- | --- | --- |",
    ...((report.deliveries || []).map((item) => `| ${line(item.cohortName || item.cohortId)} | ${line(item.dominantBlockerLabel || item.dominantBlockerCategory || "none")} | ${line(item.institutionOwnerEmail || item.recipientEmail)} | ${line(item.targetReviewAt || "not set")} | ${line(item.feedbackStatus)} | ${line(item.nextActionStatus || "none")} | ${line(item.nextCustomerSuccessAction)} |`)),
    "",
    "## Boundaries",
    ...((report.constraints || []).map((item) => `- ${line(item)}`)),
    "",
  ].join("\n");
}

function cohortProcurementProgressMeetingBrief(report) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  const summary = report.summary || {};
  const rollup = summary.institutionCsActionRollup || {};
  const deliveries = report.deliveries || [];
  const topDelivery = deliveries.find((item) => item.feedbackStatus && item.feedbackStatus !== "pending_feedback") || deliveries[0] || {};
  const decision = line(topDelivery.decisionNote || (
    summary.feedbackNeedsAction > 0
      ? "needs_more_evidence: continue education SaaS procurement review after the listed customer-success asks are closed."
      : summary.procurementReady > 0
        ? "procurement_ready: education SaaS packet review can continue with institution sign-off."
        : "continue_review: no procurement decision is recorded yet."
  ));
  const asks = [
    topDelivery.nextCustomerSuccessAction,
    summary.localSimulated > 0 ? "Replace local simulated provider evidence with production email/provider confirmation before institution handoff." : "",
    rollup.open > 0 || rollup.inProgress > 0 ? "Close open institution customer-success actions and record owner/date outcomes." : "",
    "Confirm institution compliance acknowledgement, support SLA expectation, and coach follow-through evidence.",
  ].filter(Boolean).slice(0, 5);
  const blockers = [
    ...(topDelivery.blockerCategories || []),
    ...(summary.blockerCategoryCounts || []),
  ];
  const blockerRows = blockers.length ? blockers.slice(0, 5).map((item) => (
    `- ${line(item.label || item.category || item.key)}: ${line(item.status || "needs review")} / count ${item.count || item.total || 0}. Next: ${line(item.nextCustomerSuccessAction || item.next || "assign customer-success owner and collect education evidence.")}`
  )) : ["- No blocker category is recorded yet; keep review in education customer-success mode."];
  const ownerRows = [
    `Institution owner: ${line(topDelivery.institutionOwnerEmail || topDelivery.recipientEmail || "not set")}`,
    `Customer-success owner: ${line(topDelivery.ownerEmail || rollup.byOwner?.[0]?.ownerEmail || "not set")}`,
    `Generated at: ${line(report.generatedAt)}`,
    `Target review at: ${line(topDelivery.targetReviewAt || "not set")}`,
  ];
  const ownerRollupRows = (rollup.byOwner || []).slice(0, 4).map((item) => (
    `- ${line(item.ownerEmail)}: open ${item.open || 0}, in progress ${item.inProgress || 0}, done ${item.done || 0}, high ${item.high || 0}`
  ));
  return [
    "# TradeGym Procurement Meeting Brief",
    "",
    "## Decision",
    decision,
    "",
    "## Key Asks",
    ...asks.map((item) => `- ${line(item)}`),
    "",
    "## Top Blockers",
    ...blockerRows,
    "",
    "## Owner / Date",
    ...ownerRows.map((item) => `- ${item}`),
    "",
    "## CS Action Rollup",
    `Total actions: ${rollup.totalActions || 0}. Open: ${rollup.open || 0}. In progress: ${rollup.inProgress || 0}. Done: ${rollup.done || 0}. High priority: ${rollup.high || 0}.`,
    ...(ownerRollupRows.length ? ownerRollupRows : ["- No customer-success owner rollup is recorded yet."]),
    "",
    "## Boundaries",
    "Education SaaS customer-success and procurement follow-through only; not investment advice, not trading-performance evidence, not live signal quality, not broker readiness, not auto-trading approval, and not real-money trading readiness.",
    `Production ready: ${report.productionReady}. Education only: ${report.educationOnly}.`,
    "",
  ].join("\n");
}

function cohortRenewalReviewPacket(db, cohort) {
  const successBrief = cohortSuccessBrief(db, cohort);
  const compliancePack = cohortCompliancePack(db, cohort);
  const procurementPacket = cohortProcurementPacket(db, cohort);
  const procurementProgress = cohortProcurementProgressReport(db, { cohortId: cohort.id });
  const serviceSlaActionRollup = procurementPacket.evidence?.serviceSlaActionRollup || cohortServiceSlaActionRollup(db, cohort);
  const memberIds = new Set(cohort.memberIds || []);
  const memberEmails = new Set((cohort.memberEmails || []).map((item) => String(item || "").toLowerCase()));
  const evidenceTasks = (db.coachReviewTasks || []).filter((task) => (
    task.source === "learning_evidence_followup" &&
    (memberIds.has(task.userId) || memberEmails.has(String(task.email || "").toLowerCase()))
  ));
  const evidenceLoop = learningEvidenceLoopSummary({ ...db, coachReviewTasks: evidenceTasks });
  const evidenceRows = learningEvidenceLoopRows({ ...db, coachReviewTasks: evidenceTasks }, { limit: 25 });
  const rawProcurementDeliveries = (db.cohortProcurementDeliveries || []).filter((delivery) => delivery.cohortId === cohort.id);
  const buyerHistory = rawProcurementDeliveries.flatMap((delivery) => (
    (delivery.buyerReviewHistory || []).map((review) => ({
      deliveryId: delivery.id,
      cohortId: delivery.cohortId,
      status: review.status || delivery.feedbackStatus || "needs_more_evidence",
      reviewerEmail: redactEmail(review.reviewerEmail || delivery.recipientEmail || ""),
      requestedEvidence: review.requestedEvidence || delivery.nextCustomerSuccessAction || "",
      reviewNote: review.reviewNote || "",
      createdAt: review.createdAt || delivery.feedbackAt || delivery.sentAt,
      educationOnly: true,
      productionReady: false,
    }))
  )).slice(0, 20);
  const procurementProgressBlockers = (procurementProgress.deliveries || []).flatMap((delivery) => (
    (delivery.blockerCategories || [])
      .filter((item) => ["blocked", "needs_action", "prototype_only", "watch"].includes(item.status))
      .map((item) => ({
        category: item.category || item.key,
        label: item.label || item.category || item.key,
        status: item.status,
        evidence: item.evidence || `${delivery.cohortName || cohort.name || cohort.id}: ${item.count || 0}`,
        next: item.nextCustomerSuccessAction || item.next || delivery.nextCustomerSuccessAction || "Assign an education customer-success owner.",
        educationOnly: true,
        productionReady: false,
      }))
  ));
  const renewalBlockers = [
    ...(procurementPacket.blockerCategories || [])
      .filter((item) => ["blocked", "needs_action", "prototype_only", "watch"].includes(item.status))
      .map((item) => ({
        category: item.category || item.key,
        label: item.label || item.category || item.key,
        status: item.status,
        evidence: item.evidence || "",
        next: item.nextCustomerSuccessAction || item.next || "Assign an education customer-success owner.",
        educationOnly: true,
        productionReady: false,
      })),
    ...procurementProgressBlockers,
    ...(procurementProgress.summary?.feedbackNeedsAction
      ? [{
          category: "institution_feedback",
          label: "Institution feedback",
          status: "needs_action",
          evidence: `${procurementProgress.summary.feedbackNeedsAction} procurement feedback item(s) still need customer-success action`,
          next: "Close buyer-requested evidence tasks before renewal review.",
          educationOnly: true,
          productionReady: false,
        }]
      : []),
    ...((serviceSlaActionRollup.open || 0) + (serviceSlaActionRollup.inProgress || 0)
      ? [{
          category: "support_sla",
          label: "Service SLA actions",
          status: "needs_action",
          evidence: `${serviceSlaActionRollup.open || 0} open and ${serviceSlaActionRollup.inProgress || 0} in-progress education service SLA action(s) before renewal review`,
          next: "Close education service SLA actions or record owner/status before the institution renewal review.",
          educationOnly: true,
          productionReady: false,
        }]
      : []),
    ...(evidenceLoop.backlog?.readyForCoachCompletion
      ? [{
          category: "coach_closure",
          label: "Coach closure",
          status: "needs_action",
          evidence: `${evidenceLoop.backlog.readyForCoachCompletion} completed learner assignment(s) are ready for coach closure`,
          next: "Have the coach close education evidence tasks and record notes before the institution review.",
          educationOnly: true,
          productionReady: false,
        }]
      : []),
  ].slice(0, 20);
  const renewalStatus = renewalBlockers.some((item) => ["blocked", "needs_action", "prototype_only"].includes(item.status))
    ? "renewal_review_needs_evidence"
    : successBrief.healthScore >= 75 && (compliancePack.summary?.complianceRate || 0) >= 90
      ? "education_renewal_review_ready"
      : "education_renewal_watch";
  const executiveSummary = [
    `Cohort health ${successBrief.healthScore}/100 (${successBrief.status}); compliance ${compliancePack.summary?.complianceRate || 0}%.`,
    `Learning evidence: ${successBrief.summary?.learningRecordStatements || 0} learning statement(s), ${successBrief.summary?.trainingAttempts || 0} training attempt(s), ${successBrief.summary?.completionReports || 0} completion report(s).`,
    `Procurement follow-through: ${procurementProgress.summary?.total || 0} handoff(s), ${procurementProgress.summary?.feedbackActionsDone || 0} completed institution action(s), ${procurementProgress.summary?.feedbackNeedsAction || 0} item(s) still needing action.`,
    `Evidence loop: ${evidenceLoop.assigned || 0} task(s), ${evidenceLoop.nextActionAssignmentsCompleted || 0} assignment(s) completed, ${evidenceLoop.backlog?.readyForCoachCompletion || 0} ready for coach closure.`,
    renewalBlockers.length
      ? `Renewal review should close: ${renewalBlockers.slice(0, 4).map((item) => item.label).join("; ")}.`
      : "No current code-visible renewal blocker is detected in the prototype.",
  ];
  const nextRenewalActions = [
    ...renewalBlockers.slice(0, 5).map((item) => item.next),
    ...(successBrief.nextCustomerSuccessActions || []).slice(0, 3),
    ...(compliancePack.nextComplianceActions || []).slice(0, 3),
  ].filter(Boolean).slice(0, 10);
  return {
    schemaVersion: "cohort-renewal-review-v1",
    generatedAt: new Date().toISOString(),
    cohort: successBrief.cohort,
    renewalStatus,
    executiveSummary,
    summary: {
      members: successBrief.summary?.members || 0,
      healthScore: successBrief.healthScore,
      healthStatus: successBrief.status,
      complianceRate: compliancePack.summary?.complianceRate || 0,
      complianceGaps: compliancePack.summary?.gaps || 0,
      learningRecordStatements: successBrief.summary?.learningRecordStatements || 0,
      trainingAttempts: successBrief.summary?.trainingAttempts || 0,
      completionReports: successBrief.summary?.completionReports || 0,
      procurementDeliveries: procurementProgress.summary?.total || 0,
      procurementReady: procurementProgress.summary?.procurementReady || 0,
      procurementFeedbackNeedsAction: procurementProgress.summary?.feedbackNeedsAction || 0,
      procurementActionsDone: procurementProgress.summary?.feedbackActionsDone || 0,
      buyerEvidenceRequests: buyerHistory.length,
      evidenceLoopTasks: evidenceLoop.assigned || 0,
      evidenceLoopAssignmentsCompleted: evidenceLoop.nextActionAssignmentsCompleted || 0,
      evidenceLoopReadyForCoachClosure: evidenceLoop.backlog?.readyForCoachCompletion || 0,
      serviceSlaActionsOpen: serviceSlaActionRollup.open || 0,
      serviceSlaActionsInProgress: serviceSlaActionRollup.inProgress || 0,
      serviceSlaActionsDone: serviceSlaActionRollup.done || 0,
      renewalBlockers: renewalBlockers.length,
    },
    sections: {
      successBrief: {
        schemaVersion: successBrief.schemaVersion,
        healthScore: successBrief.healthScore,
        status: successBrief.status,
        summary: successBrief.summary,
        educationOnly: true,
        productionReady: false,
      },
      compliancePack: {
        schemaVersion: compliancePack.schemaVersion,
        summary: compliancePack.summary,
        nextComplianceActions: compliancePack.nextComplianceActions,
        educationOnly: true,
        productionReady: false,
      },
      procurementPacket: {
        schemaVersion: procurementPacket.schemaVersion,
        readiness: procurementPacket.readiness,
        summary: procurementPacket.summary,
        blockerCategories: procurementPacket.blockerCategories,
        educationOnly: true,
        productionReady: false,
      },
      procurementProgress: {
        schemaVersion: procurementProgress.schemaVersion,
        summary: procurementProgress.summary,
        deliveries: (procurementProgress.deliveries || []).slice(0, 12),
        educationOnly: true,
        productionReady: false,
      },
      evidenceLoop: {
        summary: evidenceLoop,
        rows: evidenceRows,
        educationOnly: true,
        productionReady: false,
      },
      serviceSlaActionRollup,
      buyerHistory,
    },
    renewalBlockers,
    nextRenewalActions,
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort renewal review packets are education SaaS customer-success and institution review artifacts only.",
      "They combine learning adoption, compliance, support, procurement follow-through, buyer evidence requests, and coach workflow evidence.",
      "They are not investment advice, trading-performance evidence, win-rate evidence, return evidence, signal quality evidence, broker readiness, auto-trading approval, or real-money trading readiness.",
      "No stock recommendation, live signal, guaranteed return, return promise, broker connection, auto-trading, or real-money trading instruction.",
      "productionReady remains false until production identity, delivery, legal, payment, data governance, and audit-retention controls are independently verified.",
    ],
  };
}

function cohortRenewalReviewCsv(packet) {
  const columns = ["section", "metric", "value", "next", "educationOnly", "productionReady"];
  const escape = (value) => {
    const text = Array.isArray(value) ? value.join("|") : String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  const rows = [
    { section: "cohort", metric: "name", value: packet.cohort?.name || packet.cohort?.id, next: packet.renewalStatus, educationOnly: true, productionReady: false },
    ...Object.entries(packet.summary || {}).map(([metric, value]) => ({ section: "summary", metric, value, next: "", educationOnly: true, productionReady: false })),
    ...((packet.renewalBlockers || []).map((item) => ({ section: "renewal_blocker", metric: item.category, value: `${item.status}:${item.evidence}`, next: item.next, educationOnly: true, productionReady: false }))),
    ...((packet.sections?.buyerHistory || []).map((item) => ({ section: "buyer_evidence_request", metric: item.deliveryId, value: `${item.status}:${item.requestedEvidence}`, next: item.reviewNote, educationOnly: true, productionReady: false }))),
    ...((packet.nextRenewalActions || []).map((next, index) => ({ section: "next_renewal_action", metric: `action_${index + 1}`, value: "", next, educationOnly: true, productionReady: false }))),
  ];
  return [
    columns.join(","),
    ...rows.map((row) => columns.map((key) => escape(row[key])).join(",")),
  ].join("\n");
}

function cohortRenewalReviewMarkdown(packet) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  const summary = packet.summary || {};
  return [
    "# TradeGym Cohort Renewal Review",
    "",
    `Generated: ${line(packet.generatedAt)}`,
    `Cohort: ${line(packet.cohort?.name || packet.cohort?.id)}`,
    `Renewal status: ${line(packet.renewalStatus)}`,
    `Production ready: ${packet.productionReady}. Education only: ${packet.educationOnly}.`,
    "",
    "## Executive Summary",
    ...((packet.executiveSummary || []).map((item) => `- ${line(item)}`)),
    "",
    "## Renewal Metrics",
    `Members: ${summary.members || 0}. Health: ${summary.healthScore || 0}/100 (${line(summary.healthStatus)}). Compliance: ${summary.complianceRate || 0}%. Compliance gaps: ${summary.complianceGaps || 0}.`,
    `Learning statements: ${summary.learningRecordStatements || 0}. Training attempts: ${summary.trainingAttempts || 0}. Completion reports: ${summary.completionReports || 0}.`,
    `Procurement deliveries: ${summary.procurementDeliveries || 0}. Procurement ready: ${summary.procurementReady || 0}. Feedback needs action: ${summary.procurementFeedbackNeedsAction || 0}. Actions done: ${summary.procurementActionsDone || 0}.`,
    `Buyer evidence requests: ${summary.buyerEvidenceRequests || 0}. Evidence loop tasks: ${summary.evidenceLoopTasks || 0}. Evidence assignments completed: ${summary.evidenceLoopAssignmentsCompleted || 0}. Ready for coach closure: ${summary.evidenceLoopReadyForCoachClosure || 0}.`,
    `Service SLA actions: open ${summary.serviceSlaActionsOpen || 0}, in progress ${summary.serviceSlaActionsInProgress || 0}, done ${summary.serviceSlaActionsDone || 0}.`,
    "",
    "## Renewal Blockers",
    ...((packet.renewalBlockers || []).length
      ? packet.renewalBlockers.map((item) => `- ${line(item.label || item.category)}: ${line(item.status)} / ${line(item.evidence)}. Next: ${line(item.next)}`)
      : ["- No code-visible renewal blocker is detected in the prototype."]),
    "",
    "## Buyer Evidence Requests",
    ...((packet.sections?.buyerHistory || []).length
      ? packet.sections.buyerHistory.map((item) => `- ${line(item.createdAt)} / ${line(item.status)} / ${line(item.reviewerEmail)}: ${line(item.requestedEvidence || item.reviewNote)}`)
      : ["- No buyer evidence request is recorded yet."]),
    "",
    "## Next Renewal Actions",
    ...((packet.nextRenewalActions || []).map((item) => `- ${line(item)}`)),
    "",
    "## Boundaries",
    ...((packet.constraints || []).map((item) => `- ${line(item)}`)),
    "",
  ].join("\n");
}

function createCohortRenewalReviewActions(db, session, { cohortId = "", ownerEmail = "", maxCreate = 6 } = {}) {
  const cohort = (db.cohorts || []).find((item) => item.id === String(cohortId || ""));
  if (!cohort) return { error: "Cohort not found", status: 404 };
  const packet = cohortRenewalReviewPacket(db, cohort);
  const now = new Date().toISOString();
  const owner = String(ownerEmail || "success@tradegym.local").trim() || "success@tradegym.local";
  const limit = Math.min(12, Math.max(1, Number(maxCreate || 6)));
  const candidates = (packet.renewalBlockers || [])
    .filter((item) => item.status !== "ready")
    .slice(0, limit);
  db.pilotSuccessActions ||= [];
  const actions = [];
  let created = 0;
  let reused = 0;
  candidates.forEach((blocker) => {
    const category = blocker.category || "renewal_followup";
    const sourceKey = `cohort_renewal_review:${cohort.id}:${category}`;
    const existing = db.pilotSuccessActions.find((item) => item.sourceKey === sourceKey && ["open", "in_progress"].includes(item.status || "open"));
    if (existing) {
      reused += 1;
      actions.push(existing);
      return;
    }
    const priority = ["blocked", "needs_action", "prototype_only"].includes(blocker.status) ? "high" : "medium";
    const action = {
      id: `psa_${crypto.randomUUID()}`,
      sourceKey,
      criterionKey: `cohort_renewal_${category}`,
      title: `Prepare renewal review follow-up: ${blocker.label || category}`,
      status: "open",
      priority,
      ownerEmail: owner,
      evidence: [
        "Generated from TradeGym cohort renewal review.",
        `Cohort ${packet.cohort?.name || cohort.id}`,
        `Renewal status ${packet.renewalStatus}`,
        `Health ${packet.summary?.healthScore || 0}/100`,
        `Compliance ${packet.summary?.complianceRate || 0}%`,
        `Buyer evidence requests ${packet.summary?.buyerEvidenceRequests || 0}`,
        `Blocker ${blocker.label || category}: ${blocker.evidence || blocker.status}`,
      ],
      next: blocker.next || "Close this education customer-success evidence gap before institution renewal review.",
      q: cohort.name || cohort.id,
      cohortId: cohort.id,
      blockerCategory: category,
      renewalStatus: packet.renewalStatus,
      createdBy: session.userId,
      createdByEmail: session.email,
      createdAt: now,
      updatedAt: now,
      educationOnly: true,
      productionReady: false,
      constraints: [
        "Cohort renewal review actions are education SaaS customer-success follow-up tasks only.",
        "They are not investment advice, trading-performance evidence, live signal quality, broker readiness, auto-trading approval, or real-money trading readiness.",
        "Creating renewal actions does not mark the product production-ready.",
      ],
    };
    db.pilotSuccessActions.unshift(action);
    actions.push(action);
    created += 1;
  });
  db.pilotSuccessActions = db.pilotSuccessActions.slice(0, 200);
  return {
    packet,
    actions,
    created,
    reused,
    skipped: Math.max(0, (packet.renewalBlockers || []).length - candidates.length),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort renewal review actions convert education renewal blockers into customer-success tasks only.",
      "They are not investment advice, trading-performance evidence, live signal quality, broker readiness, auto-trading approval, or real-money trading readiness.",
      "productionReady remains false.",
    ],
  };
}

function createCohortProcurementDelivery(db, session, body = {}) {
  const cohort = (db.cohorts || []).find((item) => item.id === String(body.cohortId || ""));
  if (!cohort) return { error: "Cohort not found" };
  const recipientEmail = String(body.recipientEmail || body.ownerEmail || session.email || "").trim();
  if (!recipientEmail || !recipientEmail.includes("@")) return { error: "Recipient email is required" };
  const packet = cohortProcurementPacket(db, cohort);
  const provider = emailProvider.providerStatus();
  const now = new Date().toISOString();
  const delivery = {
    id: `cpd_${crypto.randomUUID()}`,
    cohortId: cohort.id,
    cohortName: cohort.name || "",
    recipientEmail,
    ownerEmail: String(body.ownerEmail || session.email || "").trim() || null,
    status: "sent",
    feedbackStatus: "pending_feedback",
    provider: provider.provider,
    providerMode: provider.mode,
    providerNote: provider.productionNote,
    subject: String(body.subject || `TradeGym cohort procurement packet: ${cohort.name || cohort.id}`).trim().slice(0, 180),
    preview: cohortProcurementPacketMarkdown(packet).slice(0, 1200),
    readiness: packet.readiness,
    packetSummary: packet.summary,
    blockerCategories: packet.blockerCategories || [],
    blockerCount: packet.blockers?.length || 0,
    sentBy: session.userId,
    sentByEmail: session.email,
    sentAt: now,
    feedbackAt: null,
    feedbackNote: "",
    nextCustomerSuccessAction: "Collect institution feedback on the education procurement packet before renewal or expansion review.",
    createdAt: now,
    updatedAt: now,
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Cohort procurement delivery is a customer-success education handoff record only.",
      "Local provider mode is simulated and does not prove production email delivery.",
      "No stock recommendation, live signal, guaranteed return, broker connection, auto-trading, or real-money trading instruction.",
    ],
  };
  db.cohortProcurementDeliveries ||= [];
  db.cohortProcurementDeliveries = [delivery, ...db.cohortProcurementDeliveries].slice(0, 200);
  return { delivery, packet };
}

function updateCohortProcurementDeliveryFeedback(db, session, body = {}) {
  const delivery = (db.cohortProcurementDeliveries || []).find((item) => item.id === String(body.deliveryId || ""));
  if (!delivery) return { error: "Cohort procurement delivery not found" };
  const feedbackStatus = String(body.feedbackStatus || delivery.feedbackStatus || "pending_feedback").trim();
  const allowed = ["pending_feedback", "objections", "needs_more_evidence", "procurement_ready", "no_fit"];
  if (!allowed.includes(feedbackStatus)) return { error: "Invalid cohort procurement feedback status" };
  const feedbackNote = String(body.feedbackNote || delivery.feedbackNote || "").trim().slice(0, 1200);
  const nextCustomerSuccessAction = String(body.nextCustomerSuccessAction || delivery.nextCustomerSuccessAction || "").trim().slice(0, 800)
    || "Plan the next education customer-success follow-up without trading-performance claims.";
  const institutionOwnerEmail = String(body.institutionOwnerEmail || delivery.institutionOwnerEmail || delivery.recipientEmail || "").trim().slice(0, 160);
  const targetReviewAt = String(body.targetReviewAt || delivery.targetReviewAt || "").trim().slice(0, 80);
  const decisionNote = String(body.decisionNote || delivery.decisionNote || "").trim().slice(0, 800);
  if (feedbackStatus !== "pending_feedback" && !feedbackNote) {
    return { error: "Feedback note is required for cohort procurement feedback outcomes" };
  }
  const adviceCheck = prohibitedAdviceCheck([feedbackNote, nextCustomerSuccessAction, decisionNote], { field: "cohortProcurementDeliveryFeedback" });
  if (adviceCheck.blocked) return { blocked: true, adviceCheck };
  const now = new Date().toISOString();
  delivery.feedbackStatus = feedbackStatus;
  delivery.feedbackNote = feedbackNote;
  delivery.nextCustomerSuccessAction = nextCustomerSuccessAction;
  delivery.feedbackAt = now;
  delivery.updatedAt = now;
  delivery.feedbackBy = session.userId;
  delivery.feedbackByEmail = session.email;
  delivery.institutionOwnerEmail = institutionOwnerEmail || null;
  delivery.targetReviewAt = targetReviewAt || null;
  delivery.decisionNote = decisionNote;
  delivery.educationOnly = true;
  delivery.productionReady = false;
  return { delivery };
}

function redactEmail(value = "") {
  const email = String(value || "");
  const [name, domain] = email.split("@");
  if (!name || !domain) return email ? "redacted" : "";
  return `${name.slice(0, 2)}***@${domain}`;
}

function cohortProcurementBuyerReviewPackage(db, delivery) {
  const cohort = (db.cohorts || []).find((item) => item.id === delivery.cohortId);
  const packet = cohort ? cohortProcurementPacket(db, cohort) : null;
  const complianceLearners = packet?.evidence?.compliancePack?.learnerSample || [];
  const redactedLearnerSample = complianceLearners.slice(0, 8).map((learner) => ({
    learnerId: learner.userId || learner.id || "learner",
    email: redactEmail(learner.email),
    legalAccepted: learner.legalAccepted === true,
    educationRiskAcknowledged: learner.educationRiskAcknowledged === true,
    emailVerified: learner.emailVerified === true,
    gaps: learner.gaps || [],
    educationOnly: true,
    productionReady: false,
  }));
  const checklist = (packet?.blockerCategories || delivery.blockerCategories || []).map((item) => ({
    category: item.category || item.key,
    label: item.label || item.category || item.key,
    status: item.status || "watch",
    count: item.count || 0,
    evidence: item.evidence || "",
    buyerQuestion: item.status === "ready"
      ? "Buyer can confirm this evidence remains current."
      : item.nextCustomerSuccessAction || item.next || "Buyer should request the missing education evidence before sign-off.",
    educationOnly: true,
    productionReady: false,
  }));
  const objectionHistory = (delivery.buyerReviewHistory || []).slice(0, 20);
  return {
    schemaVersion: "cohort-procurement-buyer-review-package-v1",
    generatedAt: new Date().toISOString(),
    deliveryId: delivery.id,
    cohortId: delivery.cohortId,
    cohortName: delivery.cohortName || packet?.cohort?.name || "",
    recipientEmail: delivery.recipientEmail,
    institutionOwnerEmail: delivery.institutionOwnerEmail || delivery.recipientEmail,
    targetReviewAt: delivery.targetReviewAt || null,
    feedbackStatus: delivery.feedbackStatus || "pending_feedback",
    readiness: packet?.readiness || delivery.readiness || "procurement_review_gaps",
    packetSummary: packet?.summary || delivery.packetSummary || {},
    redactedLearnerSample,
    checklist,
    objectionHistory,
    nextCustomerSuccessAction: delivery.nextCustomerSuccessAction || "Collect institution feedback on the education procurement packet.",
    buyerReviewStatus: objectionHistory[0]?.reviewStatus || "awaiting_buyer_review",
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Buyer review packages are institution-facing education SaaS evidence only.",
      "Redacted learner samples show onboarding/compliance evidence without exposing unnecessary personal data.",
      "Buyer objections and sign-off notes are not trading-performance evidence, signal quality evidence, broker readiness, automation approval, or real-money readiness.",
    ],
  };
}

function recordCohortProcurementBuyerObjection(db, session, body = {}) {
  const delivery = (db.cohortProcurementDeliveries || []).find((item) => item.id === String(body.deliveryId || ""));
  if (!delivery) return { error: "Cohort procurement delivery not found" };
  const reviewStatus = String(body.reviewStatus || "needs_more_evidence").trim();
  const allowed = ["awaiting_buyer_review", "objection_logged", "needs_more_evidence", "buyer_ready_for_signoff", "buyer_no_fit"];
  if (!allowed.includes(reviewStatus)) return { error: "Invalid buyer review status" };
  const reviewerEmail = String(body.reviewerEmail || delivery.institutionOwnerEmail || delivery.recipientEmail || "").trim().slice(0, 160);
  const objectionType = String(body.objectionType || "evidence_gap").trim().slice(0, 80);
  const reviewNote = String(body.reviewNote || "").trim().slice(0, 1200);
  const requestedEvidence = String(body.requestedEvidence || "").trim().slice(0, 1000);
  const targetReviewAt = String(body.targetReviewAt || delivery.targetReviewAt || "").trim().slice(0, 80);
  if (!reviewNote && reviewStatus !== "awaiting_buyer_review") {
    return { error: "Buyer review note is required" };
  }
  const adviceCheck = prohibitedAdviceCheck([reviewNote, requestedEvidence], { field: "cohortProcurementBuyerReview" });
  if (adviceCheck.blocked) return { blocked: true, adviceCheck };
  const now = new Date().toISOString();
  const review = {
    id: `cpbr_${crypto.randomUUID()}`,
    deliveryId: delivery.id,
    cohortId: delivery.cohortId,
    reviewStatus,
    reviewerEmail,
    objectionType,
    reviewNote,
    requestedEvidence,
    targetReviewAt: targetReviewAt || null,
    recordedBy: session.userId,
    recordedByEmail: session.email,
    createdAt: now,
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Buyer review notes are procurement follow-through evidence for education SaaS only.",
      "They cannot approve trading performance, live signals, broker readiness, automation, or real-money readiness.",
    ],
  };
  delivery.buyerReviewHistory ||= [];
  delivery.buyerReviewHistory = [review, ...delivery.buyerReviewHistory].slice(0, 50);
  delivery.buyerReviewStatus = reviewStatus;
  delivery.institutionOwnerEmail = reviewerEmail || delivery.institutionOwnerEmail || delivery.recipientEmail;
  delivery.targetReviewAt = targetReviewAt || delivery.targetReviewAt || null;
  delivery.updatedAt = now;
  if (["objection_logged", "needs_more_evidence"].includes(reviewStatus)) {
    delivery.feedbackStatus = "needs_more_evidence";
    delivery.feedbackNote = reviewNote;
    delivery.nextCustomerSuccessAction = requestedEvidence || "Collect requested education evidence for buyer review.";
    delivery.feedbackAt = now;
  } else if (reviewStatus === "buyer_ready_for_signoff") {
    delivery.feedbackStatus = "procurement_ready";
    delivery.feedbackNote = reviewNote;
    delivery.nextCustomerSuccessAction = "Prepare education SaaS procurement sign-off packet without production-readiness claims.";
    delivery.feedbackAt = now;
  } else if (reviewStatus === "buyer_no_fit") {
    delivery.feedbackStatus = "no_fit";
    delivery.feedbackNote = reviewNote;
    delivery.nextCustomerSuccessAction = "Close buyer review and record no-fit rationale for education SaaS customer-success learning.";
    delivery.feedbackAt = now;
  }
  delivery.educationOnly = true;
  delivery.productionReady = false;
  return { delivery, review, package: cohortProcurementBuyerReviewPackage(db, delivery) };
}

function completionCertificateFromReport(report) {
  const issuedAt = report.createdAt || report.completedAt || new Date().toISOString();
  const verificationCode = crypto
    .createHash("sha256")
    .update([report.id, report.userId, report.coursePackageId, issuedAt].join("|"))
    .digest("hex")
    .slice(0, 16);
  return {
    schemaVersion: "education-completion-certificate-v1",
    id: `cert_${report.id}`,
    reportId: report.id,
    verificationCode,
    issuedAt,
    learner: {
      id: report.userId,
      email: report.email,
      name: report.learnerName,
    },
    course: {
      id: report.coursePackageId,
      title: report.coursePackageTitle,
      version: report.courseVersion || 1,
    },
    completion: {
      percent: report.progress?.percent ?? 0,
      completedItems: report.progress?.completedItems ?? 0,
      totalItems: report.progress?.totalItems ?? 0,
      trainingAttempts: report.practiceSummary?.trainingAttempts ?? 0,
      averageRiskDiscipline: report.practiceSummary?.averageRiskDiscipline ?? null,
      topMistakeTags: report.practiceSummary?.topMistakeTags || [],
    },
    statements: [
      "This certificate confirms completion of an education-only course package workflow.",
      "It is not trading skill certification, investment advice, a win-rate claim, a return claim, a live signal, broker readiness, auto-trading approval, or real-money trading readiness.",
      "Any real-world trading decision remains outside this product and requires independent judgment and licensed advice where applicable.",
    ],
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Education completion certificates are learner-progress records only.",
      "No stock recommendation, live signal, guaranteed return, broker connection, auto-trading, or real-money trading instruction.",
    ],
  };
}

function completionCertificateCsv(certificate) {
  const columns = [
    "id",
    "reportId",
    "verificationCode",
    "issuedAt",
    "learnerEmail",
    "learnerName",
    "courseTitle",
    "courseVersion",
    "percent",
    "completedItems",
    "totalItems",
    "trainingAttempts",
    "averageRiskDiscipline",
    "educationOnly",
    "productionReady",
  ];
  const row = {
    id: certificate.id,
    reportId: certificate.reportId,
    verificationCode: certificate.verificationCode,
    issuedAt: certificate.issuedAt,
    learnerEmail: certificate.learner.email,
    learnerName: certificate.learner.name,
    courseTitle: certificate.course.title,
    courseVersion: certificate.course.version,
    percent: certificate.completion.percent,
    completedItems: certificate.completion.completedItems,
    totalItems: certificate.completion.totalItems,
    trainingAttempts: certificate.completion.trainingAttempts,
    averageRiskDiscipline: certificate.completion.averageRiskDiscipline,
    educationOnly: certificate.educationOnly,
    productionReady: certificate.productionReady,
  };
  const escape = (value) => {
    const text = String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  return [columns.join(","), columns.map((key) => escape(row[key])).join(",")].join("\n");
}

function completionCertificateMarkdown(certificate) {
  const line = (value) => String(value ?? "").replace(/\s+/g, " ").trim();
  return [
    "# TradeGym Education Completion Certificate",
    "",
    `Certificate ID: ${line(certificate.id)}`,
    `Verification code: ${line(certificate.verificationCode)}`,
    `Issued: ${line(certificate.issuedAt)}`,
    "",
    "## Learner",
    `${line(certificate.learner.name || certificate.learner.email)} (${line(certificate.learner.email)})`,
    "",
    "## Course",
    `${line(certificate.course.title)} v${line(certificate.course.version)}`,
    "",
    "## Completion Evidence",
    `Progress: ${certificate.completion.percent}% (${certificate.completion.completedItems}/${certificate.completion.totalItems} education items).`,
    `Training attempts: ${certificate.completion.trainingAttempts}. Average risk discipline: ${certificate.completion.averageRiskDiscipline ?? "not enough data"}.`,
    certificate.completion.topMistakeTags?.length
      ? `Mistake tags for continued learning: ${certificate.completion.topMistakeTags.map((item) => `${line(item.tag)} x${item.count}`).join(", ")}.`
      : "Mistake tags for continued learning: not enough data.",
    "",
    "## Boundary",
    ...certificate.statements.map((item) => `- ${line(item)}`),
    ...certificate.constraints.map((item) => `- ${line(item)}`),
    "",
  ].join("\n");
}

function supportSlaReport(db, { q = "", status = "all", limit = 100, openLimit = 8 } = {}) {
  const ticketSummary = supportTicketSummary(db, { q, status, limit });
  const sla = serviceSlaQueue(db, { limit, openLimit });
  const service = serviceDeliveryDashboard(db, { q, limit });
  const openTickets = (ticketSummary.tickets || []).filter((item) => !["resolved", "closed"].includes(item.status));
  const refundTickets = (db.supportTickets || []).filter((item) => item.category === "billing" && item.refundOrderId);
  const pendingRefunds = refundTickets.filter((item) => !item.refundStatus && !["resolved", "closed"].includes(item.status));
  const generatedAt = new Date().toISOString();
  const constraints = [
    "Support/SLA reports are education-service operating records only.",
    "No stock recommendation, live signal, guaranteed return, return promise, broker connection, auto-trading, or real-money trading instruction.",
    "Support staff must route investing, tax, legal, or personalized financial advice requests outside this product.",
    "Demo/mock/local/rule-based providers remain clearly labeled; productionReady is false.",
  ];
  const recommendations = [
    sla.summary?.highPriority ? `${sla.summary.highPriority} high-priority SLA item(s) need same-day education support triage.` : null,
    ticketSummary.summary?.overdue ? `${ticketSummary.summary.overdue} support ticket(s) are past SLA and need owner assignment.` : null,
    pendingRefunds.length ? `${pendingRefunds.length} billing refund request(s) need policy-only processing.` : null,
    sla.summary?.overLimitCoaches ? `${sla.summary.overLimitCoaches} coach queue(s) are at or above the open-task limit; rebalance before assigning normal-priority follow-ups.` : null,
    service.summary?.needsFollowUp ? `${service.summary.needsFollowUp} delivered learner report(s) need education follow-up.` : null,
    !openTickets.length && !sla.summary?.total ? "No open support/SLA backlog in the current filter." : null,
  ].filter(Boolean);
  return {
    schemaVersion: "support-sla-ops-report-v1",
    generatedAt,
    filters: { q, status, limit, openLimit },
    educationOnly: true,
    productionReady: false,
    summary: {
      totalTickets: ticketSummary.summary?.total || 0,
      openTickets: ticketSummary.summary?.open || 0,
      triagedTickets: ticketSummary.summary?.triaged || 0,
      waitingOnLearner: ticketSummary.summary?.waitingOnLearner || 0,
      resolvedTickets: ticketSummary.summary?.resolved || 0,
      overdueTickets: ticketSummary.summary?.overdue || 0,
      returnedTickets: ticketSummary.tickets?.length || 0,
      slaItems: sla.summary?.total || 0,
      highPrioritySlaItems: sla.summary?.highPriority || 0,
      serviceFollowUps: sla.summary?.serviceFollowUps || 0,
      openCoachTasks: sla.summary?.openCoachTasks || 0,
      overLimitCoaches: sla.summary?.overLimitCoaches || 0,
      refundRequests: refundTickets.length,
      pendingRefundRequests: pendingRefunds.length,
    },
    tickets: ticketSummary.tickets || [],
    queue: sla.queue || [],
    workload: sla.workload || null,
    serviceDelivery: {
      summary: service.summary || {},
      items: service.items || [],
      educationOnly: true,
    },
    refundQueue: pendingRefunds.slice(0, limit).map((ticket) => ({
      ticketId: ticket.id,
      userId: ticket.userId,
      email: ticket.email,
      learnerName: ticket.learnerName,
      refundOrderId: ticket.refundOrderId,
      status: ticket.status,
      refundStatus: ticket.refundStatus || "pending",
      createdAt: ticket.createdAt,
      educationOnly: true,
    })),
    recommendations,
    constraints,
  };
}

function supportSlaReportCsv(report) {
  const columns = [
    "kind",
    "id",
    "email",
    "learnerName",
    "status",
    "priority",
    "ageHours",
    "dueAt",
    "reason",
    "nextAction",
    "educationOnly",
    "productionReady",
  ];
  const escape = (value) => {
    const text = String(value ?? "");
    return /[",\n]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text;
  };
  const ticketRows = (report.tickets || []).map((ticket) => ({
    kind: "support_ticket",
    id: ticket.id,
    email: ticket.email,
    learnerName: ticket.learnerName,
    status: ticket.status,
    priority: ticket.priority || "normal",
    ageHours: ticket.ageHours,
    dueAt: ticket.slaDueAt || "",
    reason: ticket.subject || ticket.category || "",
    nextAction: ticket.overdue ? "Assign owner and resolve education-service SLA breach." : "Continue education-service support workflow.",
    educationOnly: true,
    productionReady: false,
  }));
  const queueRows = (report.queue || []).map((item) => ({
    kind: item.type || "sla_item",
    id: item.sourceId || item.id,
    email: item.email,
    learnerName: item.learnerName,
    status: item.status,
    priority: item.priority || "normal",
    ageHours: item.ageHours,
    dueAt: item.dueAt || item.dueLabel || "",
    reason: item.reason || "",
    nextAction: item.nextAction || "",
    educationOnly: true,
    productionReady: false,
  }));
  const rows = [...ticketRows, ...queueRows];
  return [
    columns.join(","),
    ...rows.map((row) => columns.map((key) => escape(row[key])).join(",")),
  ].join("\n");
}

