function rosterOnboardingProgressReport(db, { cohortId = "", q = "" } = {}) {
  const query = String(q || "").trim().toLowerCase();
  const reports = (db.rosterImportHandoffs || [])
    .filter((handoff) => !cohortId || handoff.cohort?.id === cohortId)
    .map((handoff) => rosterOnboardingReport(db, handoff))
    .filter((report) => !query || [
      report.handoffId,
      report.cohort?.id,
      report.cohort?.name,
      ...(report.learners || []).flatMap((learner) => [learner.email, learner.name, learner.currentStepId, learner.nextOpsAction]),
    ].filter(Boolean).some((value) => String(value).toLowerCase().includes(query)));
  const targetReviewAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
  const learners = reports.flatMap((report) => (report.learners || []).map((learner) => {
    const blockerCategory = !learner.loggedIn
      ? "first_login"
      : !learner.emailVerified
        ? "email_verification"
        : !learner.complianceAcknowledged
          ? "education_risk_acknowledgement"
          : !learner.trainingAttempts
            ? "first_training"
            : "on_track";
    return {
      handoffId: report.handoffId,
      cohortId: report.cohort?.id || null,
      cohortName: report.cohort?.name || "",
      userId: learner.userId,
      email: learner.email,
      name: learner.name,
      loggedIn: learner.loggedIn,
      emailVerified: learner.emailVerified,
      complianceAcknowledged: learner.complianceAcknowledged,
      trainingAttempts: learner.trainingAttempts || 0,
      onboardingPercent: learner.onboardingPercent || 0,
      currentStepId: learner.currentStepId,
      blockerCategory,
      status: learner.needsAttention ? "needs_followup" : "on_track",
      ownerEmail: "success@tradegym.local",
      targetReviewAt,
      nextOpsAction: learner.nextOpsAction,
      decision: learner.needsAttention ? "continue_onboarding_followup" : "monitor_weekly",
      educationOnly: true,
      productionReady: false,
    };
  }));
  const blockerCounts = ["first_login", "email_verification", "education_risk_acknowledgement", "first_training", "on_track"].map((key) => ({
    key,
    label: key.replaceAll("_", " "),
    count: learners.filter((item) => item.blockerCategory === key).length,
    needsAttention: learners.filter((item) => item.blockerCategory === key && item.status === "needs_followup").length,
  })).filter((item) => item.count > 0);
  return {
    schemaVersion: "roster-onboarding-progress-v1",
    generatedAt: new Date().toISOString(),
    filters: { cohortId: cohortId || null, q: q || null },
    summary: {
      handoffs: reports.length,
      cohorts: new Set(reports.map((item) => item.cohort?.id).filter(Boolean)).size,
      learners: learners.length,
      loggedIn: learners.filter((item) => item.loggedIn).length,
      emailVerified: learners.filter((item) => item.emailVerified).length,
      complianceAcknowledged: learners.filter((item) => item.complianceAcknowledged).length,
      startedTraining: learners.filter((item) => item.trainingAttempts > 0).length,
      needsAttention: learners.filter((item) => item.status === "needs_followup").length,
      onTrack: learners.filter((item) => item.status === "on_track").length,
      blockerCounts,
    },
    learners,
    nextMeetingAsks: learners
      .filter((item) => item.status === "needs_followup")
      .slice(0, 10)
      .map((item) => `${item.email}: ${item.nextOpsAction}`),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Roster onboarding progress is an institution customer-success meeting view for education cohort activation only.",
      "It is not investment advice, a trading signal, win-rate evidence, broker readiness, auto-trading approval, or real-money trading readiness.",
      "Temporary passwords and local verification tokens are prototype handoff artifacts, not production identity delivery proof.",
    ],
  };
}

