function createCustomerTrialKickoffActions(db, session, { ownerEmail = "", maxCreate = 8 } = {}) {
  const plan = customerTrialKickoffPlan(db);
  const owner = String(ownerEmail || "success@tradegym.local").trim() || "success@tradegym.local";
  const limit = Math.min(12, Math.max(1, Number(maxCreate || 8)));
  const candidates = (plan.steps || []).filter((item) => item.actionRecommended).slice(0, limit);
  const now = new Date().toISOString();
  db.pilotSuccessActions ||= [];
  const actions = [];
  const createdActionIds = [];
  let created = 0;
  let reused = 0;
  for (const step of candidates) {
    const sourceKey = `customer_trial_kickoff:${step.key}`;
    const existing = db.pilotSuccessActions.find((item) => item.sourceKey === sourceKey && ["open", "in_progress"].includes(item.status || "open"));
    if (existing) {
      reused += 1;
      actions.push(existing);
      continue;
    }
    const action = {
      id: `psa_${crypto.randomUUID()}`,
      sourceKey,
      criterionKey: `customer_trial_kickoff_${step.key}`,
      title: `Customer trial kickoff: ${step.title}`,
      status: "open",
      priority: step.priority === "high" ? "high" : "medium",
      ownerEmail: step.ownerEmail || owner,
      evidence: [
        `Kickoff decision ${plan.decision}`,
        `Customer trial readiness ${plan.scorecard?.customerTrialReadinessScore || 0}/100`,
        ...(step.evidence || []),
      ],
      next: step.next,
      q: step.key,
      kickoffStepKey: step.key,
      createdBy: session.userId,
      createdByEmail: session.email,
      createdAt: now,
      updatedAt: now,
      educationOnly: true,
      productionReady: false,
      constraints: [
        "Customer trial kickoff actions are education SaaS customer-success tasks only.",
        "They do not provide stock recommendations, live signals, return promises, broker connectivity, auto-trading, or real-money trading instructions.",
        "Creating kickoff actions does not mark the product production-ready.",
      ],
    };
    db.pilotSuccessActions.unshift(action);
    actions.push(action);
    createdActionIds.push(action.id);
    created += 1;
  }
  db.pilotSuccessActions = db.pilotSuccessActions.slice(0, 200);
  return {
    plan,
    actions,
    created,
    reused,
    createdActionIds,
    skipped: Math.max(0, (plan.steps || []).filter((item) => item.actionRecommended).length - candidates.length),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Customer trial kickoff actions convert education trial steps into customer-success tasks only.",
      "They are not investment advice, trading-performance evidence, live signal quality, broker readiness, auto-trading approval, or real-money trading readiness.",
      "productionReady remains false.",
    ],
  };
}

