function updatePilotExpansionPlan(db, session, body = {}) {
  const plan = (db.pilotExpansionPlans || []).find((item) => item.id === String(body.planId || ""));
  if (!plan) return { error: "Pilot expansion plan not found", status: 404 };
  const status = String(body.status || plan.status || "draft").trim();
  if (!["draft", "approved", "in_progress", "completed", "deferred"].includes(status)) {
    return { error: "Invalid pilot expansion plan status", status: 400 };
  }
  const executionNote = String(body.executionNote || plan.executionNote || "").trim().slice(0, 1000);
  const adviceCheck = prohibitedAdviceCheck(executionNote, { field: "pilotExpansionExecutionNote" });
  if (adviceCheck.blocked) return { adviceCheck, status: 422 };

  const now = new Date().toISOString();
  plan.status = status;
  plan.ownerEmail = String(body.ownerEmail || plan.ownerEmail || "").trim() || null;
  plan.executionNote = executionNote;
  plan.updatedAt = now;
  plan.updatedBy = session.userId;
  plan.updatedByEmail = session.email;
  if (status === "approved") plan.approvedAt ||= now;
  if (status === "in_progress") plan.startedAt ||= now;
  if (status === "completed") plan.completedAt ||= now;
  if (status === "deferred") plan.deferredAt ||= now;
  plan.educationOnly = true;
  plan.productionReady = false;
  return { plan, status: 200 };
}

function pilotExpansionLaunchChecklist(db, { planId = "", q = "" } = {}) {
  const query = String(q || "").trim().toLowerCase();
  const plans = (db.pilotExpansionPlans || []);
  const selectedPlan = plans.find((item) => item.id === String(planId || ""))
    || plans.find((item) => ["approved", "in_progress"].includes(item.status || "draft"))
    || plans[0]
    || null;
  const cohorts = (db.cohorts || []).map((cohort) => cohortSummary(db, cohort));
  const publishedPackages = (db.coursePackages || [])
    .filter((item) => item.status === "published")
    .map((item) => coursePackageSummary(db, item));
  const workload = coachWorkloadSummary(db, { openLimit: 8 });
  const coachCapacityRemaining = workload.coaches?.reduce((sum, item) => sum + Math.max(0, item.capacityRemaining || 0), 0) || 0;
  const readiness = productOperatingReadiness(db);
  const openActions = (db.pilotSuccessActions || []).filter((item) => ["open", "in_progress"].includes(item.status || "open"));
  const expansionFeedback = (db.pilotRenewalBriefDeliveries || []).filter((item) => ["expansion_interest", "renewal_ready"].includes(item.feedbackStatus));
  const selectedCohort = cohorts.find((item) => !query || [item.name, item.status, ...(item.memberEmails || [])]
    .filter(Boolean)
    .some((value) => String(value).toLowerCase().includes(query))) || cohorts[0] || null;
  const selectedPackage = publishedPackages.find((item) => !query || [item.title, item.status]
    .filter(Boolean)
    .some((value) => String(value).toLowerCase().includes(query))) || publishedPackages[0] || null;
  const checklist = [
    {
      key: "plan_approved",
      title: "Expansion plan approved for education delivery",
      status: selectedPlan && ["approved", "in_progress", "completed"].includes(selectedPlan.status || "draft") ? "ready" : "needs_action",
      evidence: selectedPlan ? `${selectedPlan.title || selectedPlan.id} / ${selectedPlan.status || "draft"}` : "No saved expansion plan found",
      next: selectedPlan ? "Confirm owner and first-wave scope before assigning learners." : "Save and approve an education-only pilot expansion plan.",
      educationOnly: true,
      productionReady: false,
    },
    {
      key: "cohort_ready",
      title: "First learner cohort ready",
      status: selectedCohort?.memberCount ? "ready" : "needs_action",
      evidence: selectedCohort ? `${selectedCohort.name}: ${selectedCohort.memberCount} learner(s)` : "No active learner cohort found",
      next: selectedCohort ? "Use this cohort as the first education delivery wave." : "Create a small learner cohort before expansion launch.",
      educationOnly: true,
      productionReady: false,
    },
    {
      key: "package_ready",
      title: "Reviewed course package published",
      status: selectedPackage ? "ready" : "needs_action",
      evidence: selectedPackage ? `${selectedPackage.title}: ${selectedPackage.scenarioCount || 0} scenario(s)` : "No published course package found",
      next: selectedPackage ? "Assign the package only as education practice, with source labels visible." : "Publish a reviewed education package before assigning learners.",
      educationOnly: true,
      productionReady: false,
    },
    {
      key: "coach_capacity",
      title: "Coach capacity visible",
      status: coachCapacityRemaining > 0 ? "ready" : "needs_action",
      evidence: `${coachCapacityRemaining} capacity slot(s), ${workload.totalOpen || 0} open coach task(s)`,
      next: workload.recommendations?.[0] || "Name an owner for first-wave follow-up before launch.",
      educationOnly: true,
      productionReady: false,
    },
    {
      key: "customer_success_followups",
      title: "Customer-success follow-ups controlled",
      status: openActions.length <= 3 ? "ready" : "watch",
      evidence: `${openActions.length} open/in-progress pilot action(s), ${expansionFeedback.length} renewal/expansion feedback record(s)`,
      next: openActions.length ? "Close or explicitly defer blocking follow-ups before expanding the pilot." : "Keep renewal feedback linked to education follow-up actions.",
      educationOnly: true,
      productionReady: false,
    },
    {
      key: "production_boundary",
      title: "Production trading boundary remains closed",
      status: readiness.productionReady === false ? "ready" : "blocked",
      evidence: `productionReady=${readiness.productionReady}, readiness gaps=${readiness.summary.gaps}`,
      next: "Keep provider labels demo/local/mock/rule-based and do not present expansion as real-money trading readiness.",
      educationOnly: true,
      productionReady: false,
    },
  ];
  return {
    reportType: "pilot_expansion_launch_checklist",
    generatedAt: new Date().toISOString(),
    plan: selectedPlan,
    selectedCohort,
    selectedPackage,
    checklist,
    summary: {
      total: checklist.length,
      ready: checklist.filter((item) => item.status === "ready").length,
      watch: checklist.filter((item) => item.status === "watch").length,
      needsAction: checklist.filter((item) => item.status === "needs_action").length,
      blocked: checklist.filter((item) => item.status === "blocked").length,
    },
    nextLaunchActions: checklist
      .filter((item) => item.status !== "ready")
      .map((item) => item.next)
      .slice(0, 6),
    educationOnly: true,
    productionReady: false,
    constraints: [
      "Pilot expansion launch checklist is for education SaaS delivery coordination only.",
      "It does not provide stock recommendations, live signals, return promises, broker connectivity, auto-trading, or real-money trading instructions.",
      "A ready launch checklist does not mark the product production-ready.",
    ],
  };
}

