function createReadinessRemediationTasks(db, session, body = {}) {
  const maxCreate = Math.min(20, Math.max(1, Number(body.maxCreate || 5)));
  const requestedKeys = Array.isArray(body.sourceKeys)
    ? new Set(body.sourceKeys.map((item) => String(item || "").trim()).filter(Boolean))
    : null;
  const candidates = readinessRemediationCandidates(db)
    .filter((candidate) => !requestedKeys || requestedKeys.has(candidate.sourceKey));
  const openSourceKeys = new Set((db.readinessRemediationTasks || [])
    .filter((task) => ["open", "in_progress"].includes(task.status || "open"))
    .map((task) => task.sourceKey));
  const now = new Date().toISOString();
  const created = [];
  candidates.forEach((candidate) => {
    if (created.length >= maxCreate || openSourceKeys.has(candidate.sourceKey)) return;
    const task = {
      id: `rrt_${crypto.randomUUID()}`,
      sourceKey: candidate.sourceKey,
      sourceType: candidate.sourceType,
      readinessKey: candidate.readinessKey,
      controlKey: candidate.controlKey || null,
      title: candidate.title,
      status: "open",
      priority: candidate.priority,
      ownerEmail: String(body.ownerEmail || "").trim() || null,
      dueAt: String(body.dueAt || "").trim() || null,
      evidence: candidate.evidence,
      next: candidate.next,
      createdBy: session.userId,
      createdByEmail: session.email,
      createdAt: now,
      updatedAt: now,
      educationOnly: true,
    };
    created.push(task);
    openSourceKeys.add(candidate.sourceKey);
  });
  db.readinessRemediationTasks ||= [];
  db.readinessRemediationTasks = [...created, ...db.readinessRemediationTasks].slice(0, 200);
  return created;
}

function completeAssignmentsForScenario(db, userId, scenarioId, attemptId) {
  const now = new Date().toISOString();
  const completed = [];
  (db.practiceAssignments || [])
    .filter((item) => item.userId === userId && item.scenarioId === scenarioId && item.status !== "completed")
    .forEach((item) => {
      item.status = "completed";
      item.completedAt = now;
      item.completedAttemptId = attemptId;
      item.updatedAt = now;
      if (item.source === "coach_session_followup" && item.coachSessionBookingId) {
        const booking = (db.coachSessionBookings || []).find((entry) => entry.id === item.coachSessionBookingId && entry.userId === userId);
        if (booking) {
          booking.postSessionCompletedAssignmentIds ||= [];
          if (!booking.postSessionCompletedAssignmentIds.includes(item.id)) {
            booking.postSessionCompletedAssignmentIds.unshift(item.id);
          }
          booking.postSessionCompletedAssignmentIds = booking.postSessionCompletedAssignmentIds.slice(0, 20);
          booking.lastPostSessionAssignmentCompletedAt = now;
          booking.postSessionOutcomeStatus = "practice_completed";
          booking.learnerReadAt = null;
          booking.learnerStatus = "unread";
          booking.updatedAt = now;
          booking.educationOnly = true;
          booking.productionReady = false;
        }
      }
      completed.push(item);
    });
  return completed;
}

